export enum Platform {
  FACEBOOK = 'Facebook',
  WOOCOMMERCE = 'WooCommerce',
  SHOPEE = 'Shopee',
  LAZADA = 'Lazada',
  TIKTOK = 'TikTok'
}

export type UserRole = 'owner' | 'employee' | 'collaborator';

export interface UserProfile {
  id: string;
  name: string;
  role: UserRole;
  avatar: string;
  assignedShopIds: string[]; // Only relevant for collaborators
}

export interface Warehouse {
  id: string;
  name: string;
  address: string;
  manager: string;
}

export interface Supplier {
  id: string;
  name: string;
  code: string;
  phone: string;
  email: string;
  address: string;
  note?: string;
}

export interface Product {
  id: string;
  name: string;
  sku: string;
  price: number;
  salePrice?: number;
  importPrice?: number; // New: Giá nhập để tính toán lợi nhuận/hòa vốn
  currency: string;
  stock: number; // Total stock across all warehouses
  minStock?: number; // Cảnh báo tồn kho tối thiểu
  maxStock?: number; // Cảnh báo tồn kho tối đa
  warehouseStocks: Record<string, number>; // Map warehouseId to quantity
  totalSold: number;
  platforms: Platform[];
  image: string; // Main image
  gallery: string[]; // List of images
  video?: string; // Video URL
  description: string;
  category: string;
  status: 'active' | 'draft' | 'out_of_stock';
}

export interface OrderItem {
  productId: string;
  name: string;
  image: string;
  sku: string;
  variant: string;
  quantity: number;
  price: number;
}

export interface Order {
  id: string;
  customerName: string;
  customerPhone?: string; // Added for manual order
  address?: string; // Added for manual order
  platform: Platform | 'Manual'; // Added Manual type
  shopId: string; 
  date: string;
  shipByDate?: string; // New: Thời hạn giao hàng cho ĐVVC
  total: number;
  shippingFee: number;
  platformFee: number; // New: Phí sàn
  tax: number;         // New: Thuế
  profit: number;      // New: Lợi nhuận
  status: 'pending' | 'processing' | 'shipping' | 'delivered' | 'cancelled' | 'returned';
  subStatus?: 'unprocessed' | 'printed' | 'packed'; 
  items: OrderItem[];
  shippingCarrier?: string;
  shippingMethod?: string; 
  isCOD: boolean;
  note?: string;
  trackingCode?: string;
}

export interface ConnectedShop {
  id: string;
  name: string;
  logo: string;
  connectedAt: string;
  expiresAt: string; 
  status: 'active' | 'expired' | 'disconnected';
}

export interface IntegrationConfig {
