import React, { useState, useMemo } from 'react';
import { 
  BookText, Upload, Filter, Search, Plus, FileText, Download, 
  Trash2, Eye, Edit3, X, Check, Calendar, User, DollarSign, 
  Loader2, ScanLine, Image as ImageIcon, BarChart3, PieChart
} from 'lucide-react';
