const formatCurrency = (value: number) => {
  return new Intl.NumberFormat('vi-VN', { style: 'currency', currency: 'VND' }).format(value);
};

const InvoiceManager: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'dashboard' | 'list' | 'upload'>('list');
  const [invoices, setInvoices] = useState<Invoice[]>(MOCK_INVOICES);
  const [searchTerm, setSearchTerm] = useState('');

  // Filters
  const [filterDate, setFilterDate] = useState('');
  const [filterStatus, setFilterStatus] = useState<string>('all');

  // Upload & OCR State
  const [uploadQueue, setUploadQueue] = useState<File[]>([]);
  const [isProcessing, setIsProcessing] = useState(false);
  const [ocrProgress, setOcrProgress] = useState(0);

  // Detail/Edit Modal
  const [selectedInvoice, setSelectedInvoice] = useState<Invoice | null>(null);
  const [isEditMode, setIsEditMode] = useState(false);
  const [editedInvoice, setEditedInvoice] = useState<Invoice | null>(null);

  // Derived Data
  const filteredInvoices = useMemo(() => {
    return invoices.filter(inv => {
      const matchesSearch = 
        inv.invoiceNumber.toLowerCase().includes(searchTerm.toLowerCase()) ||
        inv.customerName.toLowerCase().includes(searchTerm.toLowerCase()) ||
        inv.staffName.toLowerCase().includes(searchTerm.toLowerCase());

      const matchesStatus = filterStatus === 'all' || inv.status === filterStatus;
      const matchesDate = !filterDate || inv.date === filterDate;

      return matchesSearch && matchesStatus && matchesDate;
    });
  }, [invoices, searchTerm, filterStatus, filterDate]);

  const stats = useMemo(() => {
    const totalRevenue = invoices.filter(i => i.status === 'paid').reduce((acc, curr) => acc + curr.totalAmount, 0);
    const totalVAT = invoices.filter(i => i.status === 'paid').reduce((acc, curr) => acc + curr.vatAmount, 0);
    const unpaidAmount = invoices.filter(i => i.status === 'unpaid').reduce((acc, curr) => acc + curr.totalAmount, 0);

    // Monthly data for chart
    const monthlyData = [1,2,3,4,5,6].map(month => {
       const monthStr = `2025-0${month}`;
       const monthlyInvoices = invoices.filter(i => i.date.startsWith(monthStr));
       return {
          name: `Tháng ${month}`,
          revenue: monthlyInvoices.reduce((acc, curr) => acc + curr.totalAmount, 0),
          vat: monthlyInvoices.reduce((acc, curr) => acc + curr.vatAmount, 0)
       };
    });

    return { totalRevenue, totalVAT, unpaidAmount, monthlyData };
  }, [invoices]);

  // Handlers
  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files.length > 0) {
      const files = Array.from(e.target.files);
      setUploadQueue(files);
      simulateOCR(files);
    }
  };

  const simulateOCR = (files: File[]) => {
    setIsProcessing(true);
    setOcrProgress(0);

    const interval = setInterval(() => {
      setOcrProgress(prev => {
        if (prev >= 100) {
          clearInterval(interval);
          setIsProcessing(false);
          // Create mock invoices from files
          const newInvoices: Invoice[] = files.map((file, idx) => ({
             id: `INV-${Date.now()}-${idx}`,
             invoiceNumber: `OCR-${Math.floor(Math.random() * 10000)}`,
             date: new Date().toISOString().split('T')[0],
             customerName: 'Khách hàng OCR Mới',
             totalAmount: Math.floor(Math.random() * 5000000) + 100000,
             preTaxAmount: 0, // Will calculate below
             vatAmount: 0,
             vatRate: 10,
             items: 'Sản phẩm được quét tự động...',
             status: 'unpaid',
             paymentMethod: 'transfer',
             staffName: 'Admin',
             folder: 'Tháng 5/2025',
             imageUrl: URL.createObjectURL(file)
          })).map(inv => ({
             ...inv,
             preTaxAmount: Math.round(inv.totalAmount / 1.1),
             vatAmount: Math.round(inv.totalAmount - (inv.totalAmount / 1.1))
          }));

          setInvoices(prev => [...newInvoices, ...prev]);
          setUploadQueue([]);
          alert(`Đã xử lý xong ${files.length} hóa đơn!`);
          setActiveTab('list');
          return 100;
        }
        return prev + 10;
      });
    }, 300);
  };

  const handleDelete = (id: string) => {
    if (confirm('Bạn có chắc chắn muốn xóa hóa đơn này?')) {
      setInvoices(prev => prev.filter(i => i.id !== id));
      if (selectedInvoice?.id === id) setSelectedInvoice(null);
    }
  };

  const handleSaveEdit = () => {
    if (editedInvoice) {
      setInvoices(prev => prev.map(i => i.id === editedInvoice.id ? editedInvoice : i));
      setSelectedInvoice(editedInvoice);
      setIsEditMode(false);
    }
  };

  const renderDashboard = () => (
