                      <Bar dataKey="revenue" name="Doanh thu" fill="#4f46e5" barSize={40} radius={[4, 4, 0, 0]} />
                      <Bar dataKey="vat" name="Thuế VAT" fill="#f97316" barSize={40} radius={[4, 4, 0, 0]} />
