                <FileText className="text-purple-600 mb-2" />
                <h4 className="font-bold text-purple-800 text-sm">Lưu trữ đám mây</h4>
                <p className="text-xs text-purple-600 mt-1">Truy cập hóa đơn mọi lúc mọi nơi, phân loại theo thư mục.</p>
             </div>
             <div className="bg-green-50 p-4 rounded-lg border border-green-100">
                <BarChart3 className="text-green-600 mb-2" />
                <h4 className="font-bold text-green-800 text-sm">Báo cáo Thuế</h4>
                <p className="text-xs text-green-600 mt-1">Tổng hợp VAT đầu ra/đầu vào nhanh chóng.</p>
             </div>
          </div>
       </div>
    </div>
