import RealtimeReport from './components/RealtimeReport';
import Marketing from './components/Marketing';
import Auth from './components/Auth';
import FloatingAssistant from './components/FloatingAssistant';
import NotificationToast from './components/NotificationToast';
import Membership from './components/Membership';
import TaxReport from './components/TaxReport';
import TaxService from './components/TaxService';
import Tools from './components/Tools';
import InvoiceManager from './components/InvoiceManager';
import { Bell, Search, X, Box, FileText, ChevronRight, Package, Menu } from 'lucide-react';
import { MOCK_CONVERSATIONS, MOCK_PRODUCTS, MOCK_ORDERS } from './services/mockData';
import { UserProfile, Product, Order } from './types';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<UserProfile | null>(null);
  const [activeTab, setActiveTab] = useState('dashboard');
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);

  // Notification State
  const [notification, setNotification] = useState<{sender: string, avatar: string, message: string, platform: string} | null>(null);

  // Search State
  const [searchQuery, setSearchQuery] = useState('');
  const [searchResults, setSearchResults] = useState<{ products: Product[], orders: Order[] } | null>(null);
  const searchInputRef = useRef<HTMLInputElement>(null);

  // Handle Global Search
  useEffect(() => {
    if (searchQuery.length >= 3) {
      const term = searchQuery.toLowerCase();

      const foundProducts = MOCK_PRODUCTS.filter(p => 
        p.name.toLowerCase().includes(term) || 
        p.sku.toLowerCase().includes(term)
      ).slice(0, 5); // Limit to 5

      const foundOrders = MOCK_ORDERS.filter(o => 
        o.id.toLowerCase().includes(term) || 
        o.customerName.toLowerCase().includes(term)
      ).slice(0, 5); // Limit to 5

      if (foundProducts.length > 0 || foundOrders.length > 0) {
        setSearchResults({ products: foundProducts, orders: foundOrders });
      } else {
        setSearchResults({ products: [], orders: [] });
      }
    } else {
      setSearchResults(null);
    }
  }, [searchQuery]);

  // Handle ESC key to close search
  useEffect(() => {
    const handleEsc = (e: KeyboardEvent) => {
      if (e.key === 'Escape') {
        setSearchQuery('');
        setSearchResults(null);
        searchInputRef.current?.blur();
      }
    };
    window.addEventListener('keydown', handleEsc);
    return () => window.removeEventListener('keydown', handleEsc);
  }, []);

  const handleSearchResultClick = (tab: string) => {
    setActiveTab(tab);
    setSearchQuery('');
    setSearchResults(null);
    setIsSidebarOpen(false);
  };

  const formatCurrency = (value: number) => {
    return new Intl.NumberFormat('vi-VN', { style: 'currency', currency: 'VND' }).format(value);
  };

  // Simulation of Incoming Messages
  useEffect(() => {
    if (!currentUser) return;

    // Request browser permission
    if ('Notification' in window && Notification.permission === 'default') {
      Notification.requestPermission();
    }

    const randomMessages = [
      "Shop ơi mẫu này còn size M không?",
      "Tư vấn giúp mình sản phẩm này với ạ",
      "Mình chưa nhận được hàng, kiểm tra giúp mình",
      "Có mã giảm giá nào cho đơn 500k không shop?",
      "Hàng đẹp lắm, mình đánh giá 5 sao nhé!",
      "Cho mình xin ảnh thật sản phẩm qua inbox"
    ];

    const interval = setInterval(() => {
      // 30% chance to trigger a notification every check
      if (Math.random() > 0.7) {
        const randomConv = MOCK_CONVERSATIONS[Math.floor(Math.random() * MOCK_CONVERSATIONS.length)];
        const randomMsg = randomMessages[Math.floor(Math.random() * randomMessages.length)];

        // Show In-App Toast
        setNotification({
          sender: randomConv.customerName,
          avatar: randomConv.avatar,
          message: randomMsg,
          platform: randomConv.platform
        });

        // Show Browser Notification (if allowed)
        if ('Notification' in window && Notification.permission === 'granted' && document.hidden) {
          new Notification(`Tin nhắn mới từ ${randomConv.customerName}`, {
            body: randomMsg,
            icon: '/vite.svg'
          });
        }
      }
    }, 15000); // Check every 15 seconds

    return () => clearInterval(interval);
  }, [currentUser]);

  if (!currentUser) {
    return <Auth onLogin={(user) => setCurrentUser(user)} />;
  }

  const renderContent = () => {
    switch (activeTab) {
      case 'dashboard': return <Dashboard user={currentUser} />;
      case 'reports': return <RealtimeReport />;
      case 'create-order': return <CreateOrder />; 
      case 'orders': return <OrderList user={currentUser} />;
      case 'products': return <ProductList />;
      case 'inventory': return <Inventory />;
      case 'tools': return <Tools />;
      case 'marketing': return <Marketing />;
      case 'invoices': return <InvoiceManager />;
      case 'tax': return <TaxReport />;
      case 'tax-service': return <TaxService />;
      case 'messages': return <ChatSystem />;
      case 'integrations': return <Integrations user={currentUser} />;
      case 'membership': return <Membership />;
      default: return <Dashboard user={currentUser} />;
    }
  };

  return (
    <div className="min-h-screen bg-slate-50 flex overflow-hidden">
      <Sidebar 
        activeTab={activeTab} 
        setActiveTab={setActiveTab} 
        onLogout={() => setCurrentUser(null)} 
        isOpen={isSidebarOpen}
        onClose={() => setIsSidebarOpen(false)}
      />

      {/* Main Content Area */}
      <div className="flex-1 flex flex-col h-screen w-full transition-all duration-300">
        <header className="h-16 bg-white border-b border-slate-200 flex items-center justify-between px-4 md:px-8 sticky top-0 z-30 shadow-sm print:hidden shrink-0">
          <div className="flex items-center gap-3 md:gap-4 text-slate-400">
             <button 
               onClick={() => setIsSidebarOpen(true)}
               className="lg:hidden text-slate-600 hover:text-indigo-600 p-1"
             >
               <Menu size={24} />
             </button>

             <span className="capitalize text-slate-800 font-semibold text-base md:text-lg tracking-tight truncate max-w-[150px] md:max-w-none">
               {activeTab === 'dashboard' ? 'Tổng quan' : 
                activeTab === 'reports' ? 'Báo cáo Realtime' :
                activeTab === 'create-order' ? 'Tạo Đơn ngoài sàn' :
                activeTab === 'orders' ? 'Đơn hàng' :
                activeTab === 'products' ? 'Sản phẩm' :
                activeTab === 'inventory' ? 'Kho hàng' :
                activeTab === 'tools' ? 'Công cụ tiện ích' :
                activeTab === 'marketing' ? 'Marketing' :
                activeTab === 'invoices' ? 'Sổ & Hóa Đơn' :
                activeTab === 'tax' ? 'Báo cáo Thuế' :
                activeTab === 'tax-service' ? 'Dịch vụ Thuế' :
                activeTab === 'messages' ? 'Tin nhắn' :
                activeTab === 'integrations' ? 'Cấu hình hệ thống' : 'Nâng cấp tài khoản'}
             </span>
          </div>

          <div className="flex items-center gap-2 md:gap-6">
            {/* SEARCH INPUT */}
            <div className="relative hidden md:block group z-50">
              <input 
                ref={searchInputRef}
                type="text" 
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
                placeholder="Tìm đơn hàng, SKU..." 
                className={`pl-9 pr-10 py-2 bg-slate-100 border border-transparent rounded-lg text-sm focus:outline-none focus:ring-2 focus:ring-indigo-500 focus:bg-white w-48 lg:w-72 transition-all ${searchResults ? 'ring-2 ring-indigo-500 bg-white' : ''}`}
              />
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={16} />
              {searchQuery && (
                <button 
                  onClick={() => { setSearchQuery(''); setSearchResults(null); }}
                  className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-400 hover:text-slate-600"
                >
                  <X size={14} />
                </button>
              )}
            </div>

            <button className="relative text-slate-500 hover:text-indigo-600 transition-colors p-2 hover:bg-slate-50 rounded-full group" title="Thông báo">
              <Bell size={20} className="group-hover:rotate-12 transition-transform" />
              <span className="absolute top-1.5 right-1.5 w-2 h-2 bg-red-500 rounded-full border-2 border-white"></span>
            </button>

            <div className="flex items-center gap-3 md:pl-6 md:border-l border-slate-100 cursor-pointer hover:opacity-80 transition-opacity">
              <div className="text-right hidden sm:block">
                <div className="text-sm font-semibold text-slate-800">{currentUser.name}</div>
                <div className="text-xs text-slate-500 capitalize">
                  {currentUser.role === 'owner' ? 'Chủ Shop' : currentUser.role === 'employee' ? 'Nhân Viên' : 'Cộng Tác Viên'}
                </div>
              </div>
              <img src={currentUser.avatar} alt="Avatar" className="w-8 h-8 rounded-full border border-slate-200 object-cover" />
            </div>
          </div>
        </header>

        <main className="flex-1 overflow-y-auto p-4 md:p-8 relative print:p-0 print:overflow-visible bg-slate-50">
          {renderContent()}
        </main>

        {/* GLOBAL SEARCH RESULTS MODAL */}
        {searchResults && (
          <>
            <div className="fixed inset-0 bg-slate-900/20 backdrop-blur-sm z-40" onClick={() => { setSearchQuery(''); setSearchResults(null); }} />
            <div className="absolute top-16 left-1/2 -translate-x-1/2 w-[90%] md:w-[600px] bg-white rounded-xl shadow-2xl border border-slate-100 z-50 overflow-hidden max-h-[80vh] flex flex-col animate-fade-in">
              <div className="p-4 bg-slate-50 border-b border-slate-100 text-xs text-slate-500 flex justify-between">
                 <span>Kết quả tìm kiếm cho "{searchQuery}"</span>
                 <span className="flex items-center gap-1"><span className="px-1.5 py-0.5 bg-white border rounded text-[10px]">ESC</span> để đóng</span>
              </div>

              <div className="overflow-y-auto flex-1 p-2">
                {searchResults.products.length === 0 && searchResults.orders.length === 0 && (
                   <div className="p-8 text-center text-slate-500">
                     Không tìm thấy kết quả nào phù hợp.
                   </div>
                )}

                {/* PRODUCTS SECTION */}
                {searchResults.products.length > 0 && (
                  <div className="mb-4">
                    <h3 className="px-3 py-2 text-xs font-bold text-slate-400 uppercase tracking-wider flex items-center gap-2">
                      <Box size={14} /> Sản phẩm
                    </h3>
                    {searchResults.products.map(product => (
                      <div 
                        key={product.id} 
                        onClick={() => handleSearchResultClick('products')}
                        className="flex items-center gap-3 p-3 hover:bg-indigo-50 rounded-lg cursor-pointer group transition-colors"
                      >
                        <img src={product.image} className="w-10 h-10 rounded object-cover border border-slate-200" />
                        <div className="flex-1 min-w-0">
                          <div className="text-sm font-medium text-slate-800 group-hover:text-indigo-700 truncate">{product.name}</div>
                          <div className="text-xs text-slate-500 flex items-center gap-2">
                            <span className="bg-slate-100 px-1.5 rounded">{product.sku}</span>
                            <span className="text-indigo-600 font-medium">{formatCurrency(product.price)}</span>
                          </div>
                        </div>
                        <ChevronRight size={16} className="text-slate-300 group-hover:text-indigo-400" />
                      </div>
                    ))}
                  </div>
                )}

                {/* ORDERS SECTION */}
                {searchResults.orders.length > 0 && (
                  <div>
                    <h3 className="px-3 py-2 text-xs font-bold text-slate-400 uppercase tracking-wider flex items-center gap-2">
                      <FileText size={14} /> Đơn hàng
                    </h3>
                    {searchResults.orders.map(order => (
                      <div 
                        key={order.id} 
                        onClick={() => handleSearchResultClick('orders')}
                        className="flex items-center gap-3 p-3 hover:bg-indigo-50 rounded-lg cursor-pointer group transition-colors"
                      >
                        <div className="w-10 h-10 rounded bg-indigo-100 flex items-center justify-center text-indigo-600">
                           <Package size={20} />
                        </div>
                        <div className="flex-1 min-w-0">
                          <div className="text-sm font-medium text-slate-800 group-hover:text-indigo-700 flex gap-2">
                             <span>{order.id}</span>
                             <span className="text-slate-400 font-normal">| {order.customerName}</span>
                          </div>
                          <div className="text-xs text-slate-500 flex items-center gap-2">
                            <span className={`px-1.5 rounded ${order.status === 'delivered' ? 'bg-green-100 text-green-700' : 'bg-yellow-100 text-yellow-700'}`}>
                              {order.status === 'delivered' ? 'Đã giao' : order.status === 'pending' ? 'Chờ xác nhận' : 'Đang xử lý'}
                            </span>
                            <span>{order.platform}</span>
                            <span className="font-medium text-slate-700">{formatCurrency(order.total)}</span>
                          </div>
                        </div>
                        <ChevronRight size={16} className="text-slate-300 group-hover:text-indigo-400" />
                      </div>
                    ))}
                  </div>
                )}
              </div>
            </div>
          </>
        )}

        {/* Global Floating Widget */}
        <div className="print:hidden">
           <FloatingAssistant />
        </div>

        {/* Push Notification Toast */}
        {notification && (
          <NotificationToast 
            sender={notification.sender}
            avatar={notification.avatar}
            message={notification.message}
            platform={notification.platform}
            onClose={() => setNotification(null)}
            onClick={() => {
              setNotification(null);
              setActiveTab('messages');
            }}
          />
        )}
      </div>
    </div>
  );
};

export default App;

import React, { useState, useMemo } from 'react';
import { 
  BookText, Upload, Filter, Search, Plus, FileText, Download, 
  Trash2, Eye, Edit3, X, Check, Calendar, User, DollarSign, 
  Loader2, ScanLine, Image as ImageIcon, BarChart3, PieChart
} from 'lucide-react';
import { 
  BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip as RechartsTooltip, Legend, ResponsiveContainer 
} from 'recharts';
import { MOCK_INVOICES } from '../services/mockData';
import { Invoice } from '../types';

const formatCurrency = (value: number) => {
  return new Intl.NumberFormat('vi-VN', { style: 'currency', currency: 'VND' }).format(value);
};

const InvoiceManager: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'dashboard' | 'list' | 'upload'>('list');
  const [invoices, setInvoices] = useState<Invoice[]>(MOCK_INVOICES);
  const [searchTerm, setSearchTerm] = useState('');

  // Filters
  const [filterDate, setFilterDate] = useState('');
  const [filterStatus, setFilterStatus] = useState<string>('all');

  // Upload & OCR State
  const [uploadQueue, setUploadQueue] = useState<File[]>([]);
  const [isProcessing, setIsProcessing] = useState(false);
  const [ocrProgress, setOcrProgress] = useState(0);

  // Detail/Edit Modal
  const [selectedInvoice, setSelectedInvoice] = useState<Invoice | null>(null);
  const [isEditMode, setIsEditMode] = useState(false);
  const [editedInvoice, setEditedInvoice] = useState<Invoice | null>(null);

  // Derived Data
  const filteredInvoices = useMemo(() => {
    return invoices.filter(inv => {
      const matchesSearch = 
        inv.invoiceNumber.toLowerCase().includes(searchTerm.toLowerCase()) ||
        inv.customerName.toLowerCase().includes(searchTerm.toLowerCase()) ||
        inv.staffName.toLowerCase().includes(searchTerm.toLowerCase());

      const matchesStatus = filterStatus === 'all' || inv.status === filterStatus;
      const matchesDate = !filterDate || inv.date === filterDate;

      return matchesSearch && matchesStatus && matchesDate;
    });
  }, [invoices, searchTerm, filterStatus, filterDate]);

  const stats = useMemo(() => {
    const totalRevenue = invoices.filter(i => i.status === 'paid').reduce((acc, curr) => acc + curr.totalAmount, 0);
    const totalVAT = invoices.filter(i => i.status === 'paid').reduce((acc, curr) => acc + curr.vatAmount, 0);
    const unpaidAmount = invoices.filter(i => i.status === 'unpaid').reduce((acc, curr) => acc + curr.totalAmount, 0);

    // Monthly data for chart
    const monthlyData = [1,2,3,4,5,6].map(month => {
       const monthStr = `2025-0${month}`;
       const monthlyInvoices = invoices.filter(i => i.date.startsWith(monthStr));
       return {
          name: `Tháng ${month}`,
          revenue: monthlyInvoices.reduce((acc, curr) => acc + curr.totalAmount, 0),
          vat: monthlyInvoices.reduce((acc, curr) => acc + curr.vatAmount, 0)
       };
    });

    return { totalRevenue, totalVAT, unpaidAmount, monthlyData };
  }, [invoices]);

  // Handlers
  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files.length > 0) {
      const files = Array.from(e.target.files) as File[];
      setUploadQueue(files);
      simulateOCR(files);
    }
  };

  const simulateOCR = (files: File[]) => {
    setIsProcessing(true);
    setOcrProgress(0);

    const interval = setInterval(() => {
      setOcrProgress(prev => {
        if (prev >= 100) {
          clearInterval(interval);
          setIsProcessing(false);
          // Create mock invoices from files
          const newInvoices: Invoice[] = files.map((file, idx) => ({
             id: `INV-${Date.now()}-${idx}`,
             invoiceNumber: `OCR-${Math.floor(Math.random() * 10000)}`,
             date: new Date().toISOString().split('T')[0],
             customerName: 'Khách hàng OCR Mới',
             totalAmount: Math.floor(Math.random() * 5000000) + 100000,
             preTaxAmount: 0, // Will calculate below
             vatAmount: 0,
             vatRate: 10,
             items: 'Sản phẩm được quét tự động...',
             status: 'unpaid' as const,
             paymentMethod: 'transfer' as const,
             staffName: 'Admin',
             folder: 'Tháng 5/2025',
             imageUrl: URL.createObjectURL(file)
          })).map(inv => ({
             ...inv,
             preTaxAmount: Math.round(inv.totalAmount / 1.1),
             vatAmount: Math.round(inv.totalAmount - (inv.totalAmount / 1.1))
          }));

          setInvoices(prev => [...newInvoices, ...prev]);
          setUploadQueue([]);
          alert(`Đã xử lý xong ${files.length} hóa đơn!`);
          setActiveTab('list');
          return 100;
        }
        return prev + 10;
      });
    }, 300);
  };

  const handleDelete = (id: string) => {
    if (confirm('Bạn có chắc chắn muốn xóa hóa đơn này?')) {
      setInvoices(prev => prev.filter(i => i.id !== id));
      if (selectedInvoice?.id === id) setSelectedInvoice(null);
    }
  };

  const handleSaveEdit = () => {
    if (editedInvoice) {
      setInvoices(prev => prev.map(i => i.id === editedInvoice.id ? editedInvoice : i));
      setSelectedInvoice(editedInvoice);
      setIsEditMode(false);
    }
  };

  const renderDashboard = () => (
    <div className="space-y-6 animate-fade-in">
       {/* Stats Cards */}
       <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
          <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-100 flex items-center justify-between">
             <div>
                <p className="text-slate-500 text-sm font-medium">Tổng doanh thu (Đã thu)</p>
                <h3 className="text-2xl font-bold text-slate-800 mt-1">{formatCurrency(stats.totalRevenue)}</h3>
             </div>
             <div className="p-3 bg-green-50 text-green-600 rounded-lg">
                <DollarSign size={24} />
             </div>
          </div>
          <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-100 flex items-center justify-between">
             <div>
                <p className="text-slate-500 text-sm font-medium">Tổng thuế VAT đầu ra</p>
                <h3 className="text-2xl font-bold text-orange-600 mt-1">{formatCurrency(stats.totalVAT)}</h3>
             </div>
             <div className="p-3 bg-orange-50 text-orange-600 rounded-lg">
                <FileText size={24} />
             </div>
          </div>
          <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-100 flex items-center justify-between">
             <div>
                <p className="text-slate-500 text-sm font-medium">Công nợ phải thu</p>
                <h3 className="text-2xl font-bold text-red-600 mt-1">{formatCurrency(stats.unpaidAmount)}</h3>
             </div>
             <div className="p-3 bg-red-50 text-red-600 rounded-lg">
                <DollarSign size={24} />
             </div>
          </div>
       </div>

       {/* Charts */}
       <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
          <div className="lg:col-span-2 bg-white p-6 rounded-xl shadow-sm border border-slate-100">
             <h3 className="font-bold text-slate-800 mb-6">Biểu đồ Doanh thu & Thuế theo tháng</h3>
             <div className="h-80">
                <ResponsiveContainer width="100%" height="100%">
                   <BarChart data={stats.monthlyData}>
                      <CartesianGrid strokeDasharray="3 3" vertical={false} />
                      <XAxis dataKey="name" />
                      <YAxis />
                      <RechartsTooltip formatter={(value: number) => formatCurrency(value)} />
                      <Legend />
                      <Bar dataKey="revenue" name="Doanh thu" fill="#4f46e5" barSize={40} radius={[4, 4, 0, 0]} />
                      <Bar dataKey="vat" name="Thuế VAT" fill="#f97316" barSize={40} radius={[4, 4, 0, 0]} />
                   </BarChart>
                </ResponsiveContainer>
             </div>
          </div>
          <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-100">
             <h3 className="font-bold text-slate-800 mb-6">Thống kê nhanh</h3>
             <div className="space-y-4">
                <div className="flex justify-between items-center p-3 bg-slate-50 rounded-lg">
                   <span className="text-sm text-slate-600">Tổng hóa đơn</span>
                   <span className="font-bold text-slate-800">{invoices.length}</span>
                </div>
                <div className="flex justify-between items-center p-3 bg-green-50 rounded-lg">
                   <span className="text-sm text-green-700">Đã thanh toán</span>
                   <span className="font-bold text-green-700">{invoices.filter(i => i.status === 'paid').length}</span>
                </div>
                <div className="flex justify-between items-center p-3 bg-yellow-50 rounded-lg">
                   <span className="text-sm text-yellow-700">Chưa thanh toán</span>
                   <span className="font-bold text-yellow-700">{invoices.filter(i => i.status === 'unpaid').length}</span>
                </div>
                <div className="flex justify-between items-center p-3 bg-red-50 rounded-lg">
                   <span className="text-sm text-red-700">Đã hủy</span>
                   <span className="font-bold text-red-700">{invoices.filter(i => i.status === 'cancelled').length}</span>
                </div>
             </div>
          </div>
       </div>
    </div>
  );

  const renderUpload = () => (
    <div className="flex flex-col items-center justify-center py-12 animate-fade-in">
       <div className="w-full max-w-2xl text-center space-y-6">
          <div className="bg-white border-2 border-dashed border-slate-300 rounded-xl p-12 hover:border-indigo-500 transition-colors cursor-pointer relative group">
             <input 
               type="file" 
               multiple 
               accept="image/*,application/pdf"
               onChange={handleFileUpload}
               className="absolute inset-0 w-full h-full opacity-0 cursor-pointer"
             />
             <div className="flex flex-col items-center gap-4 group-hover:scale-105 transition-transform">
                <div className="w-16 h-16 bg-indigo-50 rounded-full flex items-center justify-center text-indigo-600">
                   <Upload size={32} />
                </div>
                <div>
                   <h3 className="text-xl font-bold text-slate-800">Tải lên hóa đơn</h3>
                   <p className="text-slate-500 mt-1">Kéo thả hoặc nhấn để chọn file (Ảnh, PDF)</p>
                </div>
             </div>
          </div>

          {isProcessing && (
             <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-100 w-full">
                <div className="flex justify-between items-center mb-2">
                   <span className="font-bold text-indigo-600 flex items-center gap-2">
                      <ScanLine size={18} className="animate-pulse" /> Đang xử lý OCR...
                   </span>
                   <span className="text-sm text-slate-500">{ocrProgress}%</span>
                </div>
                <div className="w-full bg-slate-100 rounded-full h-2">
                   <div 
                      className="bg-indigo-600 h-2 rounded-full transition-all duration-300"
                      style={{ width: `${ocrProgress}%` }}
                   ></div>
                </div>
                <p className="text-xs text-slate-400 mt-2 text-left">Đang trích xuất thông tin: Số hóa đơn, Ngày, Tổng tiền...</p>
             </div>
          )}

          <div className="grid grid-cols-1 md:grid-cols-3 gap-4 text-left">
             <div className="bg-blue-50 p-4 rounded-lg border border-blue-100">
                <ScanLine className="text-blue-600 mb-2" />
                <h4 className="font-bold text-blue-800 text-sm">Tự động OCR</h4>
                <p className="text-xs text-blue-600 mt-1">Hệ thống tự động đọc và điền thông tin hóa đơn chính xác.</p>
             </div>
             <div className="bg-purple-50 p-4 rounded-lg border border-purple-100">
                <FileText className="text-purple-600 mb-2" />
                <h4 className="font-bold text-purple-800 text-sm">Lưu trữ đám mây</h4>
                <p className="text-xs text-purple-600 mt-1">Truy cập hóa đơn mọi lúc mọi nơi, phân loại theo thư mục.</p>
             </div>
             <div className="bg-green-50 p-4 rounded-lg border border-green-100">
                <BarChart3 className="text-green-600 mb-2" />
                <h4 className="font-bold text-green-800 text-sm">Báo cáo Thuế</h4>
                <p className="text-xs text-green-600 mt-1">Tổng hợp VAT đầu ra/đầu vào nhanh chóng.</p>
             </div>
          </div>
       </div>
    </div>
  );

  const renderList = () => (
    <div className="space-y-4 animate-fade-in flex flex-col h-full">
       {/* Filters */}
       <div className="bg-white p-4 rounded-xl shadow-sm border border-slate-100 flex flex-wrap gap-4 items-center shrink-0">
          <div className="relative flex-1 min-w-[200px]">
             <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={16} />
             <input 
               type="text" 
               value={searchTerm}
               onChange={(e) => setSearchTerm(e.target.value)}
               placeholder="Tìm theo số HĐ, khách hàng..." 
               className="w-full pl-9 pr-4 py-2 bg-slate-50 border border-slate-200 rounded-lg text-sm focus:outline-none focus:ring-2 focus:ring-indigo-500"
             />
          </div>

          <div className="flex items-center gap-2">
             <input 
               type="date" 
               value={filterDate}
               onChange={(e) => setFilterDate(e.target.value)}
               className="border border-slate-200 rounded-lg px-3 py-2 text-sm text-slate-600 focus:outline-none focus:ring-2 focus:ring-indigo-500"
             />
          </div>

          <div className="flex items-center gap-2">
             <select 
               value={filterStatus}
               onChange={(e) => setFilterStatus(e.target.value)}
               className="border border-slate-200 rounded-lg px-3 py-2 text-sm text-slate-600 focus:outline-none focus:ring-2 focus:ring-indigo-500"
             >
                <option value="all">Tất cả trạng thái</option>
                <option value="paid">Đã thanh toán</option>
                <option value="unpaid">Chưa thanh toán</option>
                <option value="cancelled">Đã hủy</option>
             </select>
          </div>

          <button className="bg-indigo-600 text-white px-4 py-2 rounded-lg text-sm font-bold flex items-center gap-2 hover:bg-indigo-700 transition-colors">
             <Download size={16} /> Xuất Excel
          </button>
       </div>

       {/* Table */}
       <div className="bg-white rounded-xl shadow-sm border border-slate-100 overflow-hidden flex-1">
          <div className="overflow-auto h-full">
             <table className="w-full text-sm text-left">
                <thead className="bg-slate-50 text-slate-500 font-semibold border-b border-slate-200 sticky top-0 z-10">
                   <tr>
                      <th className="px-6 py-4">Số Hóa Đơn</th>
                      <th className="px-6 py-4">Ngày</th>
                      <th className="px-6 py-4">Khách hàng</th>
                      <th className="px-6 py-4 text-right">Tổng tiền</th>
                      <th className="px-6 py-4 text-right">VAT</th>
                      <th className="px-6 py-4 text-center">Trạng thái</th>
                      <th className="px-6 py-4 text-right">Hành động</th>
                   </tr>
                </thead>
                <tbody className="divide-y divide-slate-100">
                   {filteredInvoices.length === 0 ? (
                      <tr>
                         <td colSpan={7} className="text-center py-12 text-slate-400">Không tìm thấy hóa đơn nào</td>
                      </tr>
                   ) : (
                      filteredInvoices.map(inv => (
                         <tr key={inv.id} className="hover:bg-slate-50 group">
                            <td className="px-6 py-4 font-mono font-medium text-indigo-600">{inv.invoiceNumber}</td>
                            <td className="px-6 py-4 text-slate-600">{inv.date}</td>
                            <td className="px-6 py-4 font-medium text-slate-700">
                               {inv.customerName}
                               <div className="text-xs text-slate-400 font-normal">{inv.items}</div>
                            </td>
                            <td className="px-6 py-4 text-right font-bold text-slate-800">{formatCurrency(inv.totalAmount)}</td>
                            <td className="px-6 py-4 text-right text-slate-600">{formatCurrency(inv.vatAmount)}</td>
                            <td className="px-6 py-4 text-center">
                               <span className={`px-2 py-1 rounded-full text-xs font-bold ${
                                  inv.status === 'paid' ? 'bg-green-100 text-green-700' : 
                                  inv.status === 'unpaid' ? 'bg-yellow-100 text-yellow-700' : 'bg-red-100 text-red-700'
                               }`}>
                                  {inv.status === 'paid' ? 'Đã thanh toán' : inv.status === 'unpaid' ? 'Chưa thanh toán' : 'Đã hủy'}
                               </span>
                            </td>
                            <td className="px-6 py-4 text-right">
                               <div className="flex justify-end gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                                  <button onClick={() => { setSelectedInvoice(inv); setIsEditMode(false); }} className="p-1.5 text-slate-400 hover:text-indigo-600 hover:bg-indigo-50 rounded">
                                     <Eye size={18} />
                                  </button>
                                  <button onClick={() => { setSelectedInvoice(inv); setEditedInvoice(inv); setIsEditMode(true); }} className="p-1.5 text-slate-400 hover:text-orange-600 hover:bg-orange-50 rounded">
                                     <Edit3 size={18} />
                                  </button>
                                  <button onClick={() => handleDelete(inv.id)} className="p-1.5 text-slate-400 hover:text-red-600 hover:bg-red-50 rounded">
                                     <Trash2 size={18} />
                                  </button>
                                </div>
                            </td>
                         </tr>
                      ))
                   )}
                </tbody>
             </table>
          </div>
       </div>
    </div>
  );

  return (
    <div className="h-full flex flex-col pb-6 relative">
      <div className="flex justify-between items-center mb-6 shrink-0">
        <div>
          <h2 className="text-2xl font-bold text-slate-800 flex items-center gap-2">
            <BookText className="text-indigo-600" /> Sổ & Hóa Đơn
          </h2>
          <p className="text-sm text-slate-500 mt-1">Quản lý hóa đơn bán hàng, tự động OCR và báo cáo doanh thu.</p>
        </div>
        <div className="flex bg-white rounded-lg shadow-sm border border-slate-200 p-1">
           <button 
             onClick={() => setActiveTab('list')}
             className={`px-4 py-2 rounded-md text-sm font-medium flex items-center gap-2 transition-colors ${activeTab === 'list' ? 'bg-indigo-600 text-white' : 'text-slate-600 hover:bg-slate-50'}`}
           >
              <FileText size={16} /> Danh sách
           </button>
           <button 
             onClick={() => setActiveTab('dashboard')}
             className={`px-4 py-2 rounded-md text-sm font-medium flex items-center gap-2 transition-colors ${activeTab === 'dashboard' ? 'bg-indigo-600 text-white' : 'text-slate-600 hover:bg-slate-50'}`}
           >
              <PieChart size={16} /> Báo cáo
           </button>
           <button 
             onClick={() => setActiveTab('upload')}
             className={`px-4 py-2 rounded-md text-sm font-medium flex items-center gap-2 transition-colors ${activeTab === 'upload' ? 'bg-indigo-600 text-white' : 'text-slate-600 hover:bg-slate-50'}`}
           >
              <Upload size={16} /> Tải lên
           </button>
        </div>
      </div>

      <div className="flex-1 min-h-0">
         {activeTab === 'dashboard' && renderDashboard()}
         {activeTab === 'list' && renderList()}
         {activeTab === 'upload' && renderUpload()}
      </div>

      {/* Detail/Edit Modal */}
      {selectedInvoice && (
        <div className="fixed inset-0 bg-black/50 z-[60] flex items-center justify-center backdrop-blur-sm p-4">
          <div className="bg-white rounded-xl shadow-2xl w-full max-w-5xl h-[85vh] overflow-hidden flex flex-col animate-fade-in">
             {/* Modal Header */}
             <div className="p-4 border-b border-slate-100 flex justify-between items-center bg-slate-50 shrink-0">
                <div className="flex items-center gap-3">
                   <h3 className="font-bold text-lg text-slate-800">
                      {isEditMode ? 'Chỉnh sửa hóa đơn' : 'Chi tiết hóa đơn'}
                   </h3>
                   <span className="font-mono text-indigo-600 bg-indigo-50 px-2 py-1 rounded text-sm font-bold">#{selectedInvoice.invoiceNumber}</span>
                </div>
                <div className="flex items-center gap-2">
                   {!isEditMode && (
                      <button 
                        onClick={() => { setIsEditMode(true); setEditedInvoice(selectedInvoice); }}
                        className="px-3 py-1.5 bg-white border border-slate-200 text-slate-700 rounded-lg text-sm font-medium hover:bg-slate-50 flex items-center gap-2"
                      >
                         <Edit3 size={16} /> Sửa
                      </button>
                   )}
                   <button onClick={() => { setSelectedInvoice(null); setIsEditMode(false); }} className="p-2 hover:bg-slate-200 rounded-full text-slate-500">
                      <X size={20} />
                   </button>
                </div>
             </div>

             {/* Modal Body: Split View */}
             <div className="flex-1 flex overflow-hidden">
                {/* Left: Image Viewer */}
                <div className="w-1/2 bg-slate-900 flex items-center justify-center relative group p-4">
                   {selectedInvoice.imageUrl ? (
                      <img src={selectedInvoice.imageUrl} className="max-w-full max-h-full object-contain shadow-lg" alt="Invoice" />
                   ) : (
                      <div className="text-slate-500 flex flex-col items-center">
                         <ImageIcon size={48} className="mb-2 opacity-50" />
                         <span>Không có hình ảnh</span>
                      </div>
                   )}
                </div>

                {/* Right: Form/Details */}
                <div className="w-1/2 overflow-y-auto p-6 bg-white border-l border-slate-200">
                   {isEditMode && editedInvoice ? (
                      <div className="space-y-4">
                         <div className="grid grid-cols-2 gap-4">
                            <div>
                               <label className="block text-sm font-medium text-slate-700 mb-1">Số hóa đơn</label>
                               <input type="text" value={editedInvoice.invoiceNumber} onChange={(e) => setEditedInvoice({...editedInvoice, invoiceNumber: e.target.value})} className="w-full border-slate-200 rounded-lg px-3 py-2 text-sm focus:ring-indigo-500" />
                            </div>
                            <div>
                               <label className="block text-sm font-medium text-slate-700 mb-1">Ngày chứng từ</label>
                               <input type="date" value={editedInvoice.date} onChange={(e) => setEditedInvoice({...editedInvoice, date: e.target.value})} className="w-full border-slate-200 rounded-lg px-3 py-2 text-sm focus:ring-indigo-500" />
                            </div>
                         </div>
                         <div>
                            <label className="block text-sm font-medium text-slate-700 mb-1">Khách hàng</label>
                            <input type="text" value={editedInvoice.customerName} onChange={(e) => setEditedInvoice({...editedInvoice, customerName: e.target.value})} className="w-full border-slate-200 rounded-lg px-3 py-2 text-sm focus:ring-indigo-500" />
                         </div>
                         <div>
                            <label className="block text-sm font-medium text-slate-700 mb-1">MST Khách hàng</label>
                            <input type="text" value={editedInvoice.customerTaxCode || ''} onChange={(e) => setEditedInvoice({...editedInvoice, customerTaxCode: e.target.value})} className="w-full border-slate-200 rounded-lg px-3 py-2 text-sm focus:ring-indigo-500" />
                         </div>
                         <div className="grid grid-cols-2 gap-4">
                            <div>
                               <label className="block text-sm font-medium text-slate-700 mb-1">Tổng tiền</label>
                               <input type="number" value={editedInvoice.totalAmount} onChange={(e) => setEditedInvoice({...editedInvoice, totalAmount: Number(e.target.value)})} className="w-full border-slate-200 rounded-lg px-3 py-2 text-sm focus:ring-indigo-500 font-bold" />
                            </div>
                            <div>
                               <label className="block text-sm font-medium text-slate-700 mb-1">Tiền thuế VAT</label>
                               <input type="number" value={editedInvoice.vatAmount} onChange={(e) => setEditedInvoice({...editedInvoice, vatAmount: Number(e.target.value)})} className="w-full border-slate-200 rounded-lg px-3 py-2 text-sm focus:ring-indigo-500" />
                            </div>
                         </div>
                         <div>
                            <label className="block text-sm font-medium text-slate-700 mb-1">Nội dung / Sản phẩm</label>
                            <textarea rows={3} value={editedInvoice.items} onChange={(e) => setEditedInvoice({...editedInvoice, items: e.target.value})} className="w-full border-slate-200 rounded-lg px-3 py-2 text-sm focus:ring-indigo-500" />
                         </div>
                         <div>
                            <label className="block text-sm font-medium text-slate-700 mb-1">Trạng thái</label>
                            <select value={editedInvoice.status} onChange={(e) => setEditedInvoice({...editedInvoice, status: e.target.value as any})} className="w-full border-slate-200 rounded-lg px-3 py-2 text-sm focus:ring-indigo-500">
                               <option value="paid">Đã thanh toán</option>
                               <option value="unpaid">Chưa thanh toán</option>
                               <option value="cancelled">Đã hủy</option>
                            </select>
                         </div>
                      </div>
                   ) : (
                      <div className="space-y-6">
                         <div className="grid grid-cols-2 gap-6">
                            <div>
                               <label className="text-xs text-slate-400 block mb-1">SỐ HÓA ĐƠN</label>
                               <div className="font-mono text-lg font-bold text-slate-800">{selectedInvoice.invoiceNumber}</div>
                            </div>
                            <div>
                               <label className="text-xs text-slate-400 block mb-1">NGÀY CHỨNG TỪ</label>
                               <div className="flex items-center gap-2 font-medium text-slate-700">
                                  <Calendar size={16} /> {selectedInvoice.date}
                               </div>
                            </div>
                         </div>

                         <div className="bg-slate-50 p-4 rounded-xl border border-slate-100">
                            <label className="text-xs text-slate-400 block mb-2">KHÁCH HÀNG</label>
                            <div className="font-bold text-slate-800 text-lg mb-1">{selectedInvoice.customerName}</div>
                            {selectedInvoice.customerTaxCode && (
                               <div className="text-sm text-slate-500">MST: {selectedInvoice.customerTaxCode}</div>
                            )}
                         </div>

                         <div className="space-y-3">
                            <div className="flex justify-between items-center text-sm">
                               <span className="text-slate-500">Trước thuế</span>
                               <span className="font-medium">{formatCurrency(selectedInvoice.preTaxAmount)}</span>
                            </div>
                            <div className="flex justify-between items-center text-sm">
                               <span className="text-slate-500">VAT ({selectedInvoice.vatRate}%)</span>
                               <span className="font-medium text-orange-600">{formatCurrency(selectedInvoice.vatAmount)}</span>
                            </div>
                            <div className="border-t border-slate-100 pt-3 flex justify-between items-center">
                               <span className="font-bold text-slate-800">TỔNG THANH TOÁN</span>
                               <span className="font-bold text-indigo-600 text-2xl">{formatCurrency(selectedInvoice.totalAmount)}</span>
                            </div>
                         </div>

                         <div>
                            <label className="text-xs text-slate-400 block mb-2">NỘI DUNG</label>
                            <div className="p-3 bg-slate-50 rounded-lg text-sm text-slate-700 italic border border-slate-100">
                               "{selectedInvoice.items}"
                            </div>
                         </div>

                         <div className="flex items-center gap-4 text-xs text-slate-400 pt-4 border-t border-slate-100">
                            <div className="flex items-center gap-1"><User size={12}/> {selectedInvoice.staffName}</div>
                            <div className="flex items-center gap-1"><BookText size={12}/> {selectedInvoice.folder}</div>
                         </div>
                      </div>
                   )}
                </div>
             </div>

             {/* Modal Footer */}
             {isEditMode && (
                <div className="p-4 border-t border-slate-100 bg-slate-50 flex justify-end gap-2 shrink-0">
                   <button onClick={() => setIsEditMode(false)} className="px-4 py-2 bg-white border border-slate-200 text-slate-600 rounded-lg text-sm font-medium hover:bg-slate-50">Hủy bỏ</button>
                   <button onClick={handleSaveEdit} className="px-4 py-2 bg-indigo-600 text-white rounded-lg text-sm font-bold hover:bg-indigo-700 flex items-center gap-2">
                      <Check size={16} /> Lưu thay đổi
                   </button>
                </div>
             )}
          </div>
        </div>
      )}
    </div>
  );
};

export default InvoiceManager;

export enum Platform {
  FACEBOOK = 'Facebook',
  WOOCOMMERCE = 'WooCommerce',
  SHOPEE = 'Shopee',
  LAZADA = 'Lazada',
  TIKTOK = 'TikTok'
}

export type UserRole = 'owner' | 'employee' | 'collaborator';

export interface UserProfile {
  id: string;
  name: string;
  role: UserRole;
  avatar: string;
  assignedShopIds: string[]; // Only relevant for collaborators
}

export interface Warehouse {
  id: string;
  name: string;
  address: string;
  manager: string;
}

export interface Supplier {
  id: string;
  name: string;
  code: string;
  phone: string;
  email: string;
  address: string;
  note?: string;
}

export interface Product {
  id: string;
  name: string;
  sku: string;
  price: number;
  salePrice?: number;
  importPrice?: number; // New: Giá nhập để tính toán lợi nhuận/hòa vốn
  currency: string;
  stock: number; // Total stock across all warehouses
  minStock?: number; // Cảnh báo tồn kho tối thiểu
  maxStock?: number; // Cảnh báo tồn kho tối đa
  warehouseStocks: Record<string, number>; // Map warehouseId to quantity
  totalSold: number;
  platforms: Platform[];
  image: string; // Main image
  gallery: string[]; // List of images
  video?: string; // Video URL
  description: string;
  category: string;
  status: 'active' | 'draft' | 'out_of_stock';
}

export interface OrderItem {
  productId: string;
  name: string;
  image: string;
  sku: string;
  variant: string;
  quantity: number;
  price: number;
}

export interface Order {
  id: string;
  customerName: string;
  customerPhone?: string; // Added for manual order
  address?: string; // Added for manual order
  platform: Platform | 'Manual'; // Added Manual type
