  date: string;
  shipByDate?: string; // New: Thời hạn giao hàng cho ĐVVC
  total: number;
  shippingFee: number;
  platformFee: number; // New: Phí sàn
  tax: number;         // New: Thuế
  profit: number;      // New: Lợi nhuận
  status: 'pending' | 'processing' | 'shipping' | 'delivered' | 'cancelled' | 'returned';
  subStatus?: 'unprocessed' | 'printed' | 'packed'; 
