  const randomFactorToday = Math.random() * 0.5 + 0.8;
  const randomFactorYest = Math.random() * 0.5 + 0.8;

  return {
    hour,
    today: i <= new Date().getHours() ? Math.floor(base * randomFactorToday) : 0, // Current time limit
    yesterday: Math.floor(base * randomFactorYest)
  };
});

