    </div>
  );

  return (
    <div className="h-full flex overflow-hidden bg-white rounded-xl shadow-sm border border-slate-200">
       {renderSideMenu()}
       {activeModule === 'ledger' ? renderLedger() : renderInvoiceList()}

       {/* Detail/Edit Modal */}
       {selectedInvoice && (
        <div className="fixed inset-0 bg-black/50 z-[60] flex items-center justify-center backdrop-blur-sm p-4">
          <div className="bg-white rounded-xl shadow-2xl w-full max-w-5xl h-[85vh] overflow-hidden flex flex-col animate-fade-in">
             <div className="p-4 border-b border-slate-100 flex justify-between items-center bg-slate-50 shrink-0">
                <div className="flex items-center gap-3">
                   <h3 className="font-bold text-lg text-slate-800">{isEditMode ? 'Chỉnh sửa hóa đơn' : 'Chi tiết hóa đơn'}</h3>
                   <span className="font-mono text-indigo-600 bg-indigo-50 px-2 py-1 rounded text-sm font-bold">#{selectedInvoice.invoiceNumber}</span>
