                           className="w-full border-slate-200 rounded-lg pl-3 pr-8 py-2 text-sm font-bold focus:ring-indigo-500"
                         />
                         <DollarSign className="absolute right-2 top-1/2 -translate-y-1/2 text-slate-400" size={14} />
                      </div>
                   </div>
                   <div>
                      <label className="block text-sm font-medium text-slate-700 mb-1">Ngày giao dịch</label>
                      <div className="relative">
                         <input 
                           type="date" 
                           value={transactionForm.date}
                           onChange={(e) => setTransactionForm({...transactionForm, date: e.target.value})}
                           className="w-full border-slate-200 rounded-lg pl-3 pr-8 py-2 text-sm focus:ring-indigo-500"
                         />
                         <Calendar className="absolute right-2 top-1/2 -translate-y-1/2 text-slate-400" size={14} />
                      </div>
                   </div>
                </div>

                <div>
                   <label className="block text-sm font-medium text-slate-700 mb-1">{transactionType === 'receipt' ? 'Người nộp tiền' : 'Người nhận tiền'}</label>
                   <div className="relative">
                      <input 
                        type="text" 
                        value={transactionForm.partnerName}
                        onChange={(e) => setTransactionForm({...transactionForm, partnerName: e.target.value})}
                        placeholder={transactionType === 'receipt' ? 'Tên khách hàng...' : 'Tên nhà cung cấp / Nhân viên...'}
                        className="w-full border-slate-200 rounded-lg pl-3 pr-8 py-2 text-sm focus:ring-indigo-500"
                      />
                      <User className="absolute right-2 top-1/2 -translate-y-1/2 text-slate-400" size={14} />
                   </div>
                </div>

                <div className="grid grid-cols-2 gap-4">
                   <div>
                      <label className="block text-sm font-medium text-slate-700 mb-1">Loại giao dịch</label>
                      <select 
                        value={transactionForm.category}
                        onChange={(e) => setTransactionForm({...transactionForm, category: e.target.value})}
                        className="w-full border-slate-200 rounded-lg px-3 py-2 text-sm focus:ring-indigo-500"
                      >
                         {transactionType === 'receipt' ? (
                            <>
                               <option value="Doanh thu bán hàng">Doanh thu bán hàng</option>
                               <option value="Thu nợ">Thu nợ khách hàng</option>
                               <option value="Nạp tiền">Nạp tiền vào quỹ</option>
                               <option value="Khác">Thu khác</option>
                            </>
                         ) : (
                            <>
                               <option value="Chi phí vận hành">Chi phí vận hành</option>
                               <option value="Nhập hàng">Thanh toán nhập hàng</option>
                               <option value="Lương nhân viên">Lương nhân viên</option>
                               <option value="Trả nợ">Trả nợ nhà cung cấp</option>
                               <option value="Khác">Chi khác</option>
                            </>
                         )}
                      </select>
                   </div>
                   <div>
                      <label className="block text-sm font-medium text-slate-700 mb-1">Hình thức</label>
                      <select 
                        value={transactionForm.method}
                        onChange={(e) => setTransactionForm({...transactionForm, method: e.target.value as 'cash' | 'bank'})}
                        className="w-full border-slate-200 rounded-lg px-3 py-2 text-sm focus:ring-indigo-500"
                      >
                         <option value="cash">Tiền mặt</option>
                         <option value="bank">Chuyển khoản</option>
                      </select>
                   </div>
                </div>

                <div>
                   <label className="block text-sm font-medium text-slate-700 mb-1">Diễn giải / Ghi chú</label>
                   <div className="relative">
                      <textarea 
                        rows={3}
                        value={transactionForm.description}
                        onChange={(e) => setTransactionForm({...transactionForm, description: e.target.value})}
                        className="w-full border-slate-200 rounded-lg pl-3 pr-8 py-2 text-sm focus:ring-indigo-500 resize-none"
                        placeholder="Nội dung chi tiết..."
                      />
                      <AlignLeft className="absolute right-2 top-3 text-slate-400" size={14} />
                   </div>
                </div>
             </div>

             <div className="p-4 border-t border-slate-100 bg-slate-50 flex justify-end gap-2 shrink-0">
                <button onClick={() => setIsTransactionModalOpen(false)} className="px-4 py-2 bg-white border border-slate-200 text-slate-600 rounded-lg text-sm font-medium hover:bg-slate-50">Hủy bỏ</button>
                <button 
                  onClick={handleSaveTransaction} 
                  className={`px-4 py-2 text-white rounded-lg text-sm font-bold flex items-center gap-2 ${transactionType === 'receipt' ? 'bg-green-600 hover:bg-green-700' : 'bg-red-600 hover:bg-red-700'}`}
                >
                   <Check size={16} /> Lưu phiếu
                </button>
             </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default InvoiceManager;

export interface Invoice {
  id: string;
  type: 'input' | 'output'; // input: Mua vào, output: Bán ra
  invoiceNumber: string;
  date: string;
  partnerName: string; // Customer or Supplier
  partnerTaxCode?: string;
  totalAmount: number; // Tổng thanh toán
  preTaxAmount: number; // Trước thuế
  vatAmount: number; // Tiền thuế
  vatRate: number; // % Thuế (0, 5, 8, 10)
  items: string; // Summary of items
  status: 'paid' | 'unpaid' | 'cancelled';
  paymentMethod: 'cash' | 'transfer' | 'card';
  staffName: string;
  imageUrl?: string; // URL of the uploaded image/pdf
  folder?: string; // e.g., "Tháng 5/2025"
}

export interface LedgerRecord {
  id: string;
  date: string;
  type: 'receipt' | 'payment'; // Thu / Chi
  amount: number;
  description: string;
  category: string; // e.g., 'Doanh thu bán hàng', 'Nhập hàng', 'Chi phí vận hành', 'Lương nhân viên'
  method: 'cash' | 'bank';
  partnerName?: string;
  relatedDocId?: string; // Invoice ID or Order ID
  attachments?: string[]; // List of file URLs/Names
}

import React, { useState, useMemo } from 'react';
import { 
  BookText, Upload, Filter, Search, Plus, FileText, Download, 
  Trash2, Eye, Edit3, X, Check, Calendar, User, DollarSign, 
  Loader2, ScanLine, Image as ImageIcon, PieChart, ArrowUpRight, ArrowDownRight, Wallet, Receipt, AlignLeft, CreditCard, Paperclip, File as FileIcon
} from 'lucide-react';
import { MOCK_INVOICES, MOCK_LEDGER_RECORDS } from '../services/mockData';
import { Invoice, LedgerRecord } from '../types';

const formatCurrency = (value: number) => {
  return new Intl.NumberFormat('vi-VN', { style: 'currency', currency: 'VND' }).format(value);
};

type ModuleType = 'ledger' | 'invoices-out' | 'invoices-in';

const InvoiceManager: React.FC = () => {
  const [activeModule, setActiveModule] = useState<ModuleType>('invoices-out');
  const [invoices, setInvoices] = useState<Invoice[]>(MOCK_INVOICES);
  const [ledgerRecords, setLedgerRecords] = useState<LedgerRecord[]>(MOCK_LEDGER_RECORDS);
  const [searchTerm, setSearchTerm] = useState('');

  // Filters
  const [filterDate, setFilterDate] = useState('');
  const [filterStatus, setFilterStatus] = useState<string>('all');

  // Upload & OCR State
  const [uploadQueue, setUploadQueue] = useState<File[]>([]);
  const [isProcessing, setIsProcessing] = useState(false);
  const [ocrProgress, setOcrProgress] = useState(0);
  const [isUploadMode, setIsUploadMode] = useState(false);

  // Detail/Edit Invoice Modal
  const [selectedInvoice, setSelectedInvoice] = useState<Invoice | null>(null);
  const [isEditMode, setIsEditMode] = useState(false);
  const [editedInvoice, setEditedInvoice] = useState<Invoice | null>(null);

  // Ledger Transaction Modal
  const [isTransactionModalOpen, setIsTransactionModalOpen] = useState(false);
  const [transactionType, setTransactionType] = useState<'receipt' | 'payment'>('receipt');
  const [transactionForm, setTransactionForm] = useState({
    amount: 0,
    date: new Date().toISOString().split('T')[0],
    category: '',
    description: '',
    partnerName: '',
    method: 'cash' as 'cash' | 'bank'
  });
  const [transactionFiles, setTransactionFiles] = useState<File[]>([]);

  // Ledger Logic
  const ledgerStats = useMemo(() => {
    const totalReceipt = ledgerRecords.filter(r => r.type === 'receipt').reduce((acc, r) => acc + r.amount, 0);
    const totalPayment = ledgerRecords.filter(r => r.type === 'payment').reduce((acc, r) => acc + r.amount, 0);
    const balance = totalReceipt - totalPayment;
    return { totalReceipt, totalPayment, balance };
  }, [ledgerRecords]);

  // Derived Data for Invoices
  const currentInvoices = useMemo(() => {
    const type = activeModule === 'invoices-in' ? 'input' : 'output';
    return invoices.filter(inv => inv.type === type);
  }, [invoices, activeModule]);

  const filteredInvoices = useMemo(() => {
    return currentInvoices.filter(inv => {
      const matchesSearch = 
        inv.invoiceNumber.toLowerCase().includes(searchTerm.toLowerCase()) ||
        inv.partnerName.toLowerCase().includes(searchTerm.toLowerCase()) ||
        inv.staffName.toLowerCase().includes(searchTerm.toLowerCase());

      const matchesStatus = filterStatus === 'all' || inv.status === filterStatus;
      const matchesDate = !filterDate || inv.date === filterDate;

      return matchesSearch && matchesStatus && matchesDate;
    });
  }, [currentInvoices, searchTerm, filterStatus, filterDate]);

  // Handlers
  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files.length > 0) {
      const files = Array.from(e.target.files) as File[];
      setUploadQueue(files);
      simulateOCR(files);
    }
  };

  const simulateOCR = (files: File[]) => {
    setIsProcessing(true);
    setOcrProgress(0);

    const interval = setInterval(() => {
      setOcrProgress(prev => {
        if (prev >= 100) {
          clearInterval(interval);
          setIsProcessing(false);
          // Create mock invoices from files
          const type: 'input' | 'output' = activeModule === 'invoices-in' ? 'input' : 'output';
          const newInvoices: Invoice[] = files.map((file, idx) => ({
             id: `INV-${Date.now()}-${idx}`,
             type: type,
             invoiceNumber: `OCR-${Math.floor(Math.random() * 10000)}`,
             date: new Date().toISOString().split('T')[0],
             partnerName: type === 'input' ? 'NCC Tự động' : 'Khách hàng OCR',
             totalAmount: Math.floor(Math.random() * 5000000) + 100000,
             preTaxAmount: 0, 
             vatAmount: 0,
             vatRate: 10,
             items: 'Sản phẩm được quét tự động...',
             status: 'unpaid' as const,
             paymentMethod: 'transfer' as const,
             staffName: 'Admin',
             folder: 'Tháng 5/2025',
             imageUrl: URL.createObjectURL(file)
          })).map(inv => ({
             ...inv,
             preTaxAmount: Math.round(inv.totalAmount / 1.1),
             vatAmount: Math.round(inv.totalAmount - (inv.totalAmount / 1.1))
          }));

          setInvoices(prev => [...newInvoices, ...prev]);
          setUploadQueue([]);
          alert(`Đã xử lý xong ${files.length} hóa đơn!`);
          setIsUploadMode(false);
          return 100;
        }
        return prev + 10;
      });
    }, 300);
  };

  const handleDelete = (id: string) => {
    if (confirm('Bạn có chắc chắn muốn xóa hóa đơn này?')) {
      setInvoices(prev => prev.filter(i => i.id !== id));
      if (selectedInvoice?.id === id) setSelectedInvoice(null);
    }
  };

  const handleSaveEdit = () => {
    if (editedInvoice) {
      setInvoices(prev => prev.map(i => i.id === editedInvoice.id ? editedInvoice : i));
      setSelectedInvoice(editedInvoice);
      setIsEditMode(false);
    }
  };

  // Transaction Handlers
  const openTransactionModal = (type: 'receipt' | 'payment') => {
    setTransactionType(type);
    setTransactionForm({
      amount: 0,
      date: new Date().toISOString().split('T')[0],
      category: type === 'receipt' ? 'Doanh thu bán hàng' : 'Chi phí vận hành',
      description: '',
      partnerName: '',
      method: 'cash'
    });
    setTransactionFiles([]);
    setIsTransactionModalOpen(true);
  };

  const handleTransactionFileSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files.length > 0) {
      setTransactionFiles(prev => [...prev, ...Array.from(e.target.files || [])]);
    }
  };

  const removeTransactionFile = (index: number) => {
    setTransactionFiles(prev => prev.filter((_, i) => i !== index));
  };

  const handleSaveTransaction = () => {
    if (transactionForm.amount <= 0) {
      alert("Số tiền phải lớn hơn 0");
      return;
    }
    if (!transactionForm.description) {
      alert("Vui lòng nhập diễn giải");
      return;
    }

    // Simulate file attachment URLs
    const attachmentUrls = transactionFiles.map(file => URL.createObjectURL(file));

    const newRecord: LedgerRecord = {
      id: `LEG-${Date.now()}`,
      type: transactionType,
      ...transactionForm,
      attachments: attachmentUrls
    };

    setLedgerRecords([newRecord, ...ledgerRecords]);
    setIsTransactionModalOpen(false);
  };

  const renderSideMenu = () => (
    <div className="w-64 bg-white border-r border-slate-200 flex flex-col shrink-0">
       <div className="p-4 border-b border-slate-100">
          <h2 className="font-bold text-slate-800 text-lg flex items-center gap-2">
             <BookText className="text-indigo-600" /> Sổ & Hóa Đơn
          </h2>
       </div>
       <nav className="p-2 space-y-1">
          <button 
            onClick={() => { setActiveModule('invoices-out'); setIsUploadMode(false); }}
            className={`w-full text-left px-4 py-3 rounded-lg text-sm font-medium flex items-center gap-3 transition-colors ${activeModule === 'invoices-out' ? 'bg-indigo-50 text-indigo-700' : 'text-slate-600 hover:bg-slate-50'}`}
          >
             <FileText size={18} /> Hóa đơn Bán ra
          </button>
          <button 
            onClick={() => { setActiveModule('invoices-in'); setIsUploadMode(false); }}
            className={`w-full text-left px-4 py-3 rounded-lg text-sm font-medium flex items-center gap-3 transition-colors ${activeModule === 'invoices-in' ? 'bg-indigo-50 text-indigo-700' : 'text-slate-600 hover:bg-slate-50'}`}
          >
             <Download size={18} /> Hóa đơn Mua vào
          </button>
          <div className="my-2 border-t border-slate-100"></div>
          <button 
            onClick={() => setActiveModule('ledger')}
            className={`w-full text-left px-4 py-3 rounded-lg text-sm font-medium flex items-center gap-3 transition-colors ${activeModule === 'ledger' ? 'bg-indigo-50 text-indigo-700' : 'text-slate-600 hover:bg-slate-50'}`}
          >
             <Wallet size={18} /> Sổ Quỹ (Thu/Chi)
          </button>
       </nav>
    </div>
  );

  const renderLedger = () => (
    <div className="flex-1 flex flex-col h-full bg-slate-50/50 p-6 animate-fade-in overflow-hidden">
       {/* Dashboard Stats */}
       <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-6">
          <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-100">
             <div className="flex items-center gap-3 mb-2">
                <div className="p-2 bg-green-50 text-green-600 rounded-lg"><ArrowDownRight size={20}/></div>
                <span className="text-sm text-slate-500 font-medium">Tổng Thu</span>
             </div>
             <div className="text-2xl font-bold text-slate-800">{formatCurrency(ledgerStats.totalReceipt)}</div>
          </div>
          <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-100">
             <div className="flex items-center gap-3 mb-2">
                <div className="p-2 bg-red-50 text-red-600 rounded-lg"><ArrowUpRight size={20}/></div>
                <span className="text-sm text-slate-500 font-medium">Tổng Chi</span>
             </div>
             <div className="text-2xl font-bold text-slate-800">{formatCurrency(ledgerStats.totalPayment)}</div>
          </div>
          <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-100">
             <div className="flex items-center gap-3 mb-2">
                <div className="p-2 bg-indigo-50 text-indigo-600 rounded-lg"><Wallet size={20}/></div>
                <span className="text-sm text-slate-500 font-medium">Tồn Quỹ</span>
             </div>
             <div className={`text-2xl font-bold ${ledgerStats.balance >= 0 ? 'text-indigo-600' : 'text-red-600'}`}>{formatCurrency(ledgerStats.balance)}</div>
          </div>
       </div>

       {/* Actions & List */}
       <div className="bg-white rounded-xl shadow-sm border border-slate-100 flex-1 flex flex-col overflow-hidden">
          <div className="p-4 border-b border-slate-100 flex justify-between items-center bg-white">
             <h3 className="font-bold text-slate-800 flex items-center gap-2">
                <Receipt size={18} className="text-slate-400" /> Sổ Chi Tiết
             </h3>
             <div className="flex gap-2">
                <button 
                  onClick={() => openTransactionModal('receipt')}
                  className="px-3 py-1.5 bg-green-50 text-green-700 border border-green-200 rounded-lg text-sm font-bold flex items-center gap-1 hover:bg-green-100"
                >
                   <Plus size={14} /> Lập Phiếu Thu
                </button>
                <button 
                  onClick={() => openTransactionModal('payment')}
                  className="px-3 py-1.5 bg-red-50 text-red-700 border border-red-200 rounded-lg text-sm font-bold flex items-center gap-1 hover:bg-red-100"
                >
                   <Plus size={14} /> Lập Phiếu Chi
                </button>
             </div>
          </div>
          <div className="flex-1 overflow-auto">
             <table className="w-full text-sm text-left">
                <thead className="bg-slate-50 text-slate-500 font-semibold border-b border-slate-100 sticky top-0 z-10">
                   <tr>
                      <th className="px-6 py-3">Ngày</th>
                      <th className="px-6 py-3">Loại</th>
                      <th className="px-6 py-3">Diễn giải</th>
                      <th className="px-6 py-3">Đối tượng</th>
                      <th className="px-6 py-3 text-right">Số tiền</th>
                      <th className="px-6 py-3 text-center">Chứng từ</th>
                   </tr>
                </thead>
                <tbody className="divide-y divide-slate-100">
                   {ledgerRecords.map((record) => (
                      <tr key={record.id} className="hover:bg-slate-50">
                         <td className="px-6 py-3 text-slate-500">{record.date}</td>
                         <td className="px-6 py-3">
                            <span className={`px-2 py-1 rounded text-xs font-bold uppercase ${record.type === 'receipt' ? 'bg-green-100 text-green-700' : 'bg-red-100 text-red-700'}`}>
                               {record.type === 'receipt' ? 'Thu' : 'Chi'}
                            </span>
                         </td>
                         <td className="px-6 py-3">
                            <div className="font-medium text-slate-700">{record.description}</div>
                            <div className="text-xs text-slate-400">{record.category}</div>
                         </td>
                         <td className="px-6 py-3 text-slate-600">{record.partnerName || '-'}</td>
                         <td className={`px-6 py-3 text-right font-bold ${record.type === 'receipt' ? 'text-green-600' : 'text-red-600'}`}>
                            {record.type === 'receipt' ? '+' : '-'}{formatCurrency(record.amount)}
                         </td>
                         <td className="px-6 py-3 text-center">
                            {record.attachments && record.attachments.length > 0 && (
                               <div className="flex justify-center gap-1">
                                  <Paperclip size={14} className="text-indigo-500" />
                                  <span className="text-xs text-indigo-600 font-medium">{record.attachments.length}</span>
                               </div>
                            )}
                         </td>
                      </tr>
                   ))}
                </tbody>
             </table>
          </div>
       </div>
    </div>
  );

  const renderInvoiceList = () => (
    <div className="flex-1 flex flex-col h-full bg-slate-50/50 p-6 animate-fade-in overflow-hidden">
       {/* Header & Actions */}
       <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4 mb-6">
          <div>
             <h2 className="text-2xl font-bold text-slate-800">
                {activeModule === 'invoices-out' ? 'Hóa đơn Bán ra' : 'Hóa đơn Mua vào'}
             </h2>
             <p className="text-sm text-slate-500">Quản lý chứng từ {activeModule === 'invoices-out' ? 'doanh thu bán hàng' : 'chi phí nhập hàng'}.</p>
          </div>
          <div className="flex gap-2">
             <button 
                onClick={() => setIsUploadMode(true)}
                className="px-4 py-2 bg-white border border-slate-200 text-slate-700 rounded-lg text-sm font-medium hover:bg-slate-50 flex items-center gap-2 shadow-sm"
             >
                <Upload size={16} /> Tải hóa đơn (OCR)
             </button>
             <button className="px-4 py-2 bg-indigo-600 text-white rounded-lg text-sm font-bold shadow-sm hover:bg-indigo-700 transition-colors flex items-center gap-2">
                <Plus size={16} /> Tạo mới
             </button>
          </div>
       </div>

       {/* Filters */}
       <div className="bg-white p-4 rounded-xl shadow-sm border border-slate-100 flex flex-wrap gap-4 items-center mb-4">
          <div className="relative flex-1 min-w-[200px]">
             <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={16} />
             <input 
               type="text" 
               value={searchTerm}
               onChange={(e) => setSearchTerm(e.target.value)}
               placeholder={`Tìm theo số HĐ, ${activeModule === 'invoices-out' ? 'khách hàng' : 'nhà cung cấp'}...`}
               className="w-full pl-9 pr-4 py-2 bg-slate-50 border border-slate-200 rounded-lg text-sm focus:outline-none focus:ring-2 focus:ring-indigo-500"
             />
          </div>
          <div className="flex items-center gap-2">
             <input type="date" value={filterDate} onChange={(e) => setFilterDate(e.target.value)} className="border border-slate-200 rounded-lg px-3 py-2 text-sm text-slate-600 focus:outline-none focus:ring-2 focus:ring-indigo-500" />
          </div>
          <select value={filterStatus} onChange={(e) => setFilterStatus(e.target.value)} className="border border-slate-200 rounded-lg px-3 py-2 text-sm text-slate-600 focus:outline-none focus:ring-2 focus:ring-indigo-500">
             <option value="all">Tất cả trạng thái</option>
             <option value="paid">Đã thanh toán</option>
             <option value="unpaid">Chưa thanh toán</option>
             <option value="cancelled">Đã hủy</option>
          </select>
       </div>

       {/* Table */}
       {isUploadMode ? (
          <div className="bg-white rounded-xl shadow-sm border border-slate-100 flex-1 flex flex-col items-center justify-center p-10 animate-fade-in relative">
             <button onClick={() => setIsUploadMode(false)} className="absolute top-4 right-4 text-slate-400 hover:text-slate-600"><X size={24}/></button>
             <div className="w-full max-w-xl text-center space-y-6">
                <div className="bg-indigo-50 border-2 border-dashed border-indigo-200 rounded-xl p-12 hover:border-indigo-500 transition-colors cursor-pointer relative group">
                   <input 
                     type="file" 
                     multiple 
                     accept="image/*,application/pdf"
                     onChange={handleFileUpload}
                     className="absolute inset-0 w-full h-full opacity-0 cursor-pointer"
                   />
                   <div className="flex flex-col items-center gap-4">
                      <div className="w-16 h-16 bg-white rounded-full flex items-center justify-center text-indigo-600 shadow-sm">
                         <ScanLine size={32} />
                      </div>
                      <div>
                         <h3 className="text-xl font-bold text-slate-800">Quét hóa đơn tự động</h3>
                         <p className="text-slate-500 mt-1">Hệ thống sẽ tự động trích xuất thông tin từ ảnh/PDF</p>
                      </div>
                   </div>
                </div>
                {isProcessing && (
                   <div className="bg-white p-4 rounded-lg border border-slate-100 shadow-sm">
                      <div className="flex justify-between items-center mb-2">
                         <span className="font-bold text-indigo-600 text-sm flex items-center gap-2"><Loader2 className="animate-spin" size={14}/> Đang xử lý OCR...</span>
                         <span className="text-xs text-slate-500">{ocrProgress}%</span>
                      </div>
                      <div className="w-full bg-slate-100 rounded-full h-1.5">
                         <div className="bg-indigo-600 h-1.5 rounded-full transition-all duration-300" style={{ width: `${ocrProgress}%` }}></div>
                      </div>
                   </div>
                )}
             </div>
          </div>
       ) : (
          <div className="bg-white rounded-xl shadow-sm border border-slate-100 overflow-hidden flex-1 flex flex-col">
             <div className="overflow-auto flex-1">
                <table className="w-full text-sm text-left">
                   <thead className="bg-slate-50 text-slate-500 font-semibold border-b border-slate-200 sticky top-0 z-10">
                      <tr>
                         <th className="px-6 py-4">Số Hóa Đơn</th>
                         <th className="px-6 py-4">Ngày</th>
                         <th className="px-6 py-4">{activeModule === 'invoices-out' ? 'Khách hàng' : 'Nhà cung cấp'}</th>
                         <th className="px-6 py-4 text-right">Tổng tiền</th>
                         <th className="px-6 py-4 text-right">VAT</th>
                         <th className="px-6 py-4 text-center">Trạng thái</th>
                         <th className="px-6 py-4 text-right">Hành động</th>
                      </tr>
                   </thead>
                   <tbody className="divide-y divide-slate-100">
                      {filteredInvoices.length === 0 ? (
                         <tr><td colSpan={7} className="text-center py-12 text-slate-400">Không tìm thấy hóa đơn nào</td></tr>
                      ) : (
                         filteredInvoices.map(inv => (
                            <tr key={inv.id} className="hover:bg-slate-50 group">
                               <td className="px-6 py-4 font-mono font-medium text-indigo-600 flex items-center gap-2">
                                  {inv.imageUrl && <ImageIcon size={14} className="text-slate-400" />} {inv.invoiceNumber}
                               </td>
                               <td className="px-6 py-4 text-slate-600">{inv.date}</td>
                               <td className="px-6 py-4 font-medium text-slate-700">
                                  {inv.partnerName}
                                  <div className="text-xs text-slate-400 font-normal truncate max-w-[200px]">{inv.items}</div>
                               </td>
                               <td className="px-6 py-4 text-right font-bold text-slate-800">{formatCurrency(inv.totalAmount)}</td>
                               <td className="px-6 py-4 text-right text-slate-600">{formatCurrency(inv.vatAmount)}</td>
                               <td className="px-6 py-4 text-center">
                                  <span className={`px-2 py-1 rounded-full text-xs font-bold ${
                                     inv.status === 'paid' ? 'bg-green-100 text-green-700' : 
                                     inv.status === 'unpaid' ? 'bg-yellow-100 text-yellow-700' : 'bg-red-100 text-red-700'
                                  }`}>
                                     {inv.status === 'paid' ? 'Đã thanh toán' : inv.status === 'unpaid' ? 'Chưa thanh toán' : 'Đã hủy'}
                                  </span>
                               </td>
                               <td className="px-6 py-4 text-right">
                                  <div className="flex justify-end gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                                     <button onClick={() => { setSelectedInvoice(inv); setIsEditMode(false); }} className="p-1.5 text-slate-400 hover:text-indigo-600 hover:bg-indigo-50 rounded"><Eye size={18} /></button>
                                     <button onClick={() => { setSelectedInvoice(inv); setEditedInvoice(inv); setIsEditMode(true); }} className="p-1.5 text-slate-400 hover:text-orange-600 hover:bg-orange-50 rounded"><Edit3 size={18} /></button>
                                     <button onClick={() => handleDelete(inv.id)} className="p-1.5 text-slate-400 hover:text-red-600 hover:bg-red-50 rounded"><Trash2 size={18} /></button>
                                  </div>
                               </td>
                            </tr>
                         ))
                      )}
                   </tbody>
                </table>
             </div>
          </div>
       )}
    </div>
  );

  return (
    <div className="h-full flex overflow-hidden bg-white rounded-xl shadow-sm border border-slate-200">
       {renderSideMenu()}
       {activeModule === 'ledger' ? renderLedger() : renderInvoiceList()}

       {/* Detail/Edit Invoice Modal */}
       {selectedInvoice && (
        <div className="fixed inset-0 bg-black/50 z-[60] flex items-center justify-center backdrop-blur-sm p-4">
          <div className="bg-white rounded-xl shadow-2xl w-full max-w-5xl h-[85vh] overflow-hidden flex flex-col animate-fade-in">
             <div className="p-4 border-b border-slate-100 flex justify-between items-center bg-slate-50 shrink-0">
                <div className="flex items-center gap-3">
                   <h3 className="font-bold text-lg text-slate-800">{isEditMode ? 'Chỉnh sửa hóa đơn' : 'Chi tiết hóa đơn'}</h3>
                   <span className="font-mono text-indigo-600 bg-indigo-50 px-2 py-1 rounded text-sm font-bold">#{selectedInvoice.invoiceNumber}</span>
                </div>
                <div className="flex items-center gap-2">
                   {!isEditMode && <button onClick={() => { setIsEditMode(true); setEditedInvoice(selectedInvoice); }} className="px-3 py-1.5 bg-white border border-slate-200 text-slate-700 rounded-lg text-sm font-medium hover:bg-slate-50 flex items-center gap-2"><Edit3 size={16} /> Sửa</button>}
                   <button onClick={() => { setSelectedInvoice(null); setIsEditMode(false); }} className="p-2 hover:bg-slate-200 rounded-full text-slate-500"><X size={20} /></button>
                </div>
             </div>

             <div className="flex-1 flex overflow-hidden">
                <div className="w-1/2 bg-slate-900 flex items-center justify-center relative group p-4">
                   {selectedInvoice.imageUrl ? <img src={selectedInvoice.imageUrl} className="max-w-full max-h-full object-contain shadow-lg" alt="Invoice" /> : <div className="text-slate-500 flex flex-col items-center"><ImageIcon size={48} className="mb-2 opacity-50" /><span>Không có hình ảnh</span></div>}
                </div>
                <div className="w-1/2 overflow-y-auto p-6 bg-white border-l border-slate-200">
                   {isEditMode && editedInvoice ? (
                      <div className="space-y-4">
                         <div className="grid grid-cols-2 gap-4">
                            <div><label className="block text-sm font-medium text-slate-700 mb-1">Số hóa đơn</label><input type="text" value={editedInvoice.invoiceNumber} onChange={(e) => setEditedInvoice({...editedInvoice, invoiceNumber: e.target.value})} className="w-full border-slate-200 rounded-lg px-3 py-2 text-sm focus:ring-indigo-500" /></div>
                            <div><label className="block text-sm font-medium text-slate-700 mb-1">Ngày chứng từ</label><input type="date" value={editedInvoice.date} onChange={(e) => setEditedInvoice({...editedInvoice, date: e.target.value})} className="w-full border-slate-200 rounded-lg px-3 py-2 text-sm focus:ring-indigo-500" /></div>
                         </div>
                         <div><label className="block text-sm font-medium text-slate-700 mb-1">{editedInvoice.type === 'output' ? 'Khách hàng' : 'Nhà cung cấp'}</label><input type="text" value={editedInvoice.partnerName} onChange={(e) => setEditedInvoice({...editedInvoice, partnerName: e.target.value})} className="w-full border-slate-200 rounded-lg px-3 py-2 text-sm focus:ring-indigo-500" /></div>
                         <div className="grid grid-cols-2 gap-4">
                            <div><label className="block text-sm font-medium text-slate-700 mb-1">Tổng tiền</label><input type="number" value={editedInvoice.totalAmount} onChange={(e) => setEditedInvoice({...editedInvoice, totalAmount: Number(e.target.value)})} className="w-full border-slate-200 rounded-lg px-3 py-2 text-sm focus:ring-indigo-500 font-bold" /></div>
                            <div><label className="block text-sm font-medium text-slate-700 mb-1">VAT</label><input type="number" value={editedInvoice.vatAmount} onChange={(e) => setEditedInvoice({...editedInvoice, vatAmount: Number(e.target.value)})} className="w-full border-slate-200 rounded-lg px-3 py-2 text-sm focus:ring-indigo-500" /></div>
                         </div>
                         <div><label className="block text-sm font-medium text-slate-700 mb-1">Trạng thái</label><select value={editedInvoice.status} onChange={(e) => setEditedInvoice({...editedInvoice, status: e.target.value as any})} className="w-full border-slate-200 rounded-lg px-3 py-2 text-sm focus:ring-indigo-500"><option value="paid">Đã thanh toán</option><option value="unpaid">Chưa thanh toán</option><option value="cancelled">Đã hủy</option></select></div>
                      </div>
                   ) : (
                      <div className="space-y-6">
                         <div className="grid grid-cols-2 gap-6">
                            <div><label className="text-xs text-slate-400 block mb-1">SỐ HÓA ĐƠN</label><div className="font-mono text-lg font-bold text-slate-800">{selectedInvoice.invoiceNumber}</div></div>
                            <div><label className="text-xs text-slate-400 block mb-1">NGÀY CHỨNG TỪ</label><div className="flex items-center gap-2 font-medium text-slate-700"><Calendar size={16} /> {selectedInvoice.date}</div></div>
                         </div>
                         <div className="bg-slate-50 p-4 rounded-xl border border-slate-100">
                            <label className="text-xs text-slate-400 block mb-2">{selectedInvoice.type === 'output' ? 'KHÁCH HÀNG' : 'NHÀ CUNG CẤP'}</label>
                            <div className="font-bold text-slate-800 text-lg mb-1">{selectedInvoice.partnerName}</div>
                            {selectedInvoice.partnerTaxCode && <div className="text-sm text-slate-500">MST: {selectedInvoice.partnerTaxCode}</div>}
                         </div>
                         <div className="space-y-3">
                            <div className="flex justify-between items-center text-sm"><span className="text-slate-500">Trước thuế</span><span className="font-medium">{formatCurrency(selectedInvoice.preTaxAmount)}</span></div>
                            <div className="flex justify-between items-center text-sm"><span className="text-slate-500">VAT ({selectedInvoice.vatRate}%)</span><span className="font-medium text-orange-600">{formatCurrency(selectedInvoice.vatAmount)}</span></div>
                            <div className="border-t border-slate-100 pt-3 flex justify-between items-center"><span className="font-bold text-slate-800">TỔNG THANH TOÁN</span><span className="font-bold text-indigo-600 text-2xl">{formatCurrency(selectedInvoice.totalAmount)}</span></div>
                         </div>
                         <div className="flex items-center gap-4 text-xs text-slate-400 pt-4 border-t border-slate-100">
                            <div className="flex items-center gap-1"><User size={12}/> {selectedInvoice.staffName}</div>
                            <div className="flex items-center gap-1"><BookText size={12}/> {selectedInvoice.folder}</div>
                         </div>
                      </div>
                   )}
                </div>
             </div>
             {isEditMode && <div className="p-4 border-t border-slate-100 bg-slate-50 flex justify-end gap-2 shrink-0"><button onClick={() => setIsEditMode(false)} className="px-4 py-2 bg-white border border-slate-200 text-slate-600 rounded-lg text-sm font-medium hover:bg-slate-50">Hủy bỏ</button><button onClick={handleSaveEdit} className="px-4 py-2 bg-indigo-600 text-white rounded-lg text-sm font-bold hover:bg-indigo-700 flex items-center gap-2"><Check size={16} /> Lưu thay đổi</button></div>}
          </div>
        </div>
      )}

      {/* Ledger Transaction Modal */}
      {isTransactionModalOpen && (
        <div className="fixed inset-0 bg-black/50 z-[60] flex items-center justify-center backdrop-blur-sm p-4">
          <div className="bg-white rounded-xl shadow-2xl w-full max-w-lg overflow-hidden animate-fade-in">
             <div className={`p-4 border-b flex justify-between items-center shrink-0 ${transactionType === 'receipt' ? 'bg-green-50 border-green-100' : 'bg-red-50 border-red-100'}`}>
                <h3 className={`font-bold text-lg flex items-center gap-2 ${transactionType === 'receipt' ? 'text-green-700' : 'text-red-700'}`}>
                   {transactionType === 'receipt' ? <ArrowDownRight size={20}/> : <ArrowUpRight size={20}/>}
                   {transactionType === 'receipt' ? 'Lập Phiếu Thu' : 'Lập Phiếu Chi'}
                </h3>
                <button onClick={() => setIsTransactionModalOpen(false)} className="text-slate-400 hover:text-slate-600"><X size={20}/></button>
             </div>

             <div className="p-6 space-y-4">
                <div className="grid grid-cols-2 gap-4">
                   <div>
                      <label className="block text-sm font-medium text-slate-700 mb-1">Số tiền</label>
                      <div className="relative">
                         <input 
                           type="number" 
                           value={transactionForm.amount}
                           onChange={(e) => setTransactionForm({...transactionForm, amount: Number(e.target.value)})}
                           className="w-full border-slate-200 rounded-lg pl-3 pr-8 py-2 text-sm font-bold focus:ring-indigo-500"
                         />
                         <DollarSign className="absolute right-2 top-1/2 -translate-y-1/2 text-slate-400" size={14} />
                      </div>
                   </div>
                   <div>
                      <label className="block text-sm font-medium text-slate-700 mb-1">Ngày giao dịch</label>
                      <div className="relative">
                         <input 
                           type="date" 
                           value={transactionForm.date}
                           onChange={(e) => setTransactionForm({...transactionForm, date: e.target.value})}
                           className="w-full border-slate-200 rounded-lg pl-3 pr-8 py-2 text-sm focus:ring-indigo-500"
                         />
                         <Calendar className="absolute right-2 top-1/2 -translate-y-1/2 text-slate-400" size={14} />
                      </div>
                   </div>
                </div>

                <div>
                   <label className="block text-sm font-medium text-slate-700 mb-1">{transactionType === 'receipt' ? 'Người nộp tiền' : 'Người nhận tiền'}</label>
                   <div className="relative">
                      <input 
                        type="text" 
                        value={transactionForm.partnerName}
                        onChange={(e) => setTransactionForm({...transactionForm, partnerName: e.target.value})}
                        placeholder={transactionType === 'receipt' ? 'Tên khách hàng...' : 'Tên nhà cung cấp / Nhân viên...'}
                        className="w-full border-slate-200 rounded-lg pl-3 pr-8 py-2 text-sm focus:ring-indigo-500"
                      />
                      <User className="absolute right-2 top-1/2 -translate-y-1/2 text-slate-400" size={14} />
                   </div>
                </div>

                <div className="grid grid-cols-2 gap-4">
                   <div>
                      <label className="block text-sm font-medium text-slate-700 mb-1">Loại giao dịch</label>
                      <select 
                        value={transactionForm.category}
                        onChange={(e) => setTransactionForm({...transactionForm, category: e.target.value})}
                        className="w-full border-slate-200 rounded-lg px-3 py-2 text-sm focus:ring-indigo-500"
                      >
                         {transactionType === 'receipt' ? (
                            <>
                               <option value="Doanh thu bán hàng">Doanh thu bán hàng</option>
                               <option value="Thu nợ">Thu nợ khách hàng</option>
                               <option value="Nạp tiền">Nạp tiền vào quỹ</option>
                               <option value="Khác">Thu khác</option>
                            </>
                         ) : (
                            <>
                               <option value="Chi phí vận hành">Chi phí vận hành</option>
                               <option value="Nhập hàng">Thanh toán nhập hàng</option>
                               <option value="Lương nhân viên">Lương nhân viên</option>
                               <option value="Trả nợ">Trả nợ nhà cung cấp</option>
                               <option value="Khác">Chi khác</option>
                            </>
                         )}
                      </select>
                   </div>
                   <div>
                      <label className="block text-sm font-medium text-slate-700 mb-1">Hình thức</label>
                      <select 
                        value={transactionForm.method}
                        onChange={(e) => setTransactionForm({...transactionForm, method: e.target.value as 'cash' | 'bank'})}
                        className="w-full border-slate-200 rounded-lg px-3 py-2 text-sm focus:ring-indigo-500"
                      >
                         <option value="cash">Tiền mặt</option>
                         <option value="bank">Chuyển khoản</option>
                      </select>
                   </div>
                </div>

                <div>
                   <label className="block text-sm font-medium text-slate-700 mb-1">Diễn giải / Ghi chú</label>
                   <div className="relative">
                      <textarea 
                        rows={3}
                        value={transactionForm.description}
                        onChange={(e) => setTransactionForm({...transactionForm, description: e.target.value})}
                        className="w-full border-slate-200 rounded-lg pl-3 pr-8 py-2 text-sm focus:ring-indigo-500 resize-none"
                        placeholder="Nội dung chi tiết..."
                      />
                      <AlignLeft className="absolute right-2 top-3 text-slate-400" size={14} />
                   </div>
                </div>

                <div>
                   <label className="block text-sm font-medium text-slate-700 mb-1">Chứng từ đính kèm</label>
                   <div className="border border-dashed border-slate-300 rounded-lg p-4 text-center cursor-pointer hover:bg-slate-50 transition-colors relative">
                      <input 
                        type="file" 
                        multiple 
                        onChange={handleTransactionFileSelect}
                        className="absolute inset-0 w-full h-full opacity-0 cursor-pointer"
                      />
                      <div className="flex flex-col items-center justify-center gap-1 text-slate-500">
                         <Paperclip size={20} />
                         <span className="text-xs">Nhấn để tải file (Ảnh, PDF)</span>
                      </div>
                   </div>
                   {transactionFiles.length > 0 && (
                      <div className="mt-2 space-y-1">
                         {transactionFiles.map((file, idx) => (
                            <div key={idx} className="flex items-center justify-between text-xs bg-slate-50 p-2 rounded border border-slate-100">
                               <div className="flex items-center gap-2 truncate">
                                  <FileIcon size={12} className="text-indigo-500 shrink-0" />
                                  <span className="truncate max-w-[200px]">{file.name}</span>
                               </div>
                               <button onClick={() => removeTransactionFile(idx)} className="text-slate-400 hover:text-red-500"><X size={12}/></button>
                            </div>
                         ))}
                      </div>
                   )}
                </div>
             </div>

             <div className="p-4 border-t border-slate-100 bg-slate-50 flex justify-end gap-2 shrink-0">
                <button onClick={() => setIsTransactionModalOpen(false)} className="px-4 py-2 bg-white border border-slate-200 text-slate-600 rounded-lg text-sm font-medium hover:bg-slate-50">Hủy bỏ</button>
                <button 
                  onClick={handleSaveTransaction} 
                  className={`px-4 py-2 text-white rounded-lg text-sm font-bold flex items-center gap-2 ${transactionType === 'receipt' ? 'bg-green-600 hover:bg-green-700' : 'bg-red-600 hover:bg-red-700'}`}
                >
                   <Check size={16} /> Lưu phiếu
                </button>
             </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default InvoiceManager;

export enum Platform {
  SHOPEE = 'Shopee',
  LAZADA = 'Lazada',
  TIKTOK = 'TikTok',
  FACEBOOK = 'Facebook',
  WOOCOMMERCE = 'WooCommerce'
}

