// Helper to distribute stock
const distributeStock = (totalStock: number): Record<string, number> => {
  const stock1 = Math.floor(totalStock * 0.6);
  const stock2 = Math.floor(totalStock * 0.3);
  const stock3 = totalStock - stock1 - stock2;
  return {
    'wh1': stock1,
    'wh2': stock2,
    'wh3': stock3
  };
};

// Helper to generate random products
const generateMockProducts = (count: number): Product[] => {
  const categories = ['Thời trang nữ', 'Thời trang nam', 'Điện tử', 'Nhà cửa & Đời sống', 'Mẹ & Bé', 'Mỹ phẩm', 'Phụ kiện'];
