const generateMockConversations = (count: number): Conversation[] => {
  const firstNames = ['An', 'Bình', 'Chi', 'Dũng', 'Giang', 'Hương', 'Khánh', 'Lan', 'Minh', 'Nam', 'Oanh', 'Phúc', 'Quân', 'Thảo', 'Uyên', 'Vinh', 'Yến', 'Tú', 'Thành', 'Hà'];
  const lastNames = ['Nguyễn', 'Trần', 'Lê', 'Phạm', 'Hoàng', 'Huỳnh', 'Phan', 'Vũ', 'Võ', 'Đặng', 'Bùi', 'Đỗ', 'Hồ', 'Ngô', 'Dương', 'Lý', 'Vương', 'Đinh', 'Trịnh'];
  const platforms = [Platform.SHOPEE, Platform.LAZADA, Platform.TIKTOK, Platform.FACEBOOK, Platform.WOOCOMMERCE];

  // Conversation scenarios
  const scenarios = [
    // Pre-sale
    { type: 'inquiry', msgs: [
      { u: 'Shop ơi mẫu này còn size M không?', s: 'Dạ còn bạn nhé, bạn khoảng bao nhiêu kg ạ?' },
      { u: 'Mình 55kg cao 1m6', s: 'Dạ 55kg mặc size M là vừa đẹp ạ.' },
      { u: 'Cảm ơn shop, để mình đặt luôn' }
    ]},
    { type: 'inquiry', msgs: [
      { u: 'Cho mình xin ảnh thật sản phẩm với', s: 'Dạ bạn chờ xíu shop gửi ngay ạ.' },
      { u: 'Ok shop', s: 'Đây ạ (Đã gửi ảnh)' },
      { u: 'Nhìn đẹp quá, chất vải gì vậy shop?', s: 'Dạ chất cotton 100% thấm hút mồ hôi ạ' }
    ]},
    { type: 'inquiry', msgs: [{ u: 'Sản phẩm này bảo hành bao lâu vậy shop?' }]},

    // Shipping
    { type: 'shipping', msgs: [
      { u: 'Shop ơi đơn của mình đi chưa?', s: 'Dạ đơn của bạn shipper vừa lấy sáng nay rồi ạ.' },
      { u: 'Khoảng bao lâu thì nhận được nhỉ?', s: 'Dạ tầm 2-3 ngày tùy khu vực ạ.' }
    ]},
    { type: 'shipping', msgs: [{ u: 'Mình muốn đổi địa chỉ nhận hàng được không?' }]},
    { type: 'shipping', msgs: [{ u: 'Sao lâu nhận được hàng thế shop? Đặt 3 ngày rồi' }]},

    // Complaint
    { type: 'complaint', msgs: [
      { u: 'Shop ơi mình nhận hàng bị rách góc', s: 'Dạ shop xin lỗi bạn nhiều ạ. Bạn chụp ảnh giúp shop để shop hỗ trợ đổi trả nhé.' },
      { u: 'Đây shop xem đi', s: 'Dạ vâng shop đã thấy. Bạn bấm hoàn hàng trên app giúp shop nha.' }
    ]},
    { type: 'complaint', msgs: [{ u: 'Giao sai màu rồi shop ơi, mình đặt Đen giao Trắng' }]},

    // Feedback
    { type: 'feedback', msgs: [{ u: 'Hàng đẹp lắm shop ơi, sẽ ủng hộ tiếp', s: 'Dạ cảm ơn bạn nhiều ạ ❤️' }]},
    { type: 'feedback', msgs: [{ u: 'Đóng gói cẩn thận, giao nhanh. 5 sao nhé', s: 'Cảm ơn bạn đã tin tưởng shop ạ!' }]},

    // Other
    { type: 'other', msgs: [{ u: 'Có freeship không shop?' }]},
    { type: 'spam', msgs: [{ u: 'Chào bạn, bên mình đang có dịch vụ tăng like...' }]}
  ];

  return Array.from({ length: count }).map((_, i) => {
    const scenario = scenarios[Math.floor(Math.random() * scenarios.length)];
    const id = `C${i + 1000}`;
    const customerName = `${lastNames[Math.floor(Math.random() * lastNames.length)]} ${firstNames[Math.floor(Math.random() * firstNames.length)]}`;
    const platform = platforms[Math.floor(Math.random() * platforms.length)];
    const avatar = `https://i.pravatar.cc/150?u=${id}`;

    // Generate messages based on scenario
    const messages: ChatMessage[] = [];
    let lastTime = new Date();
    // Randomize start time within last 3 days
    lastTime.setMinutes(lastTime.getMinutes() - Math.floor(Math.random() * 4320)); 

    scenario.msgs.forEach((m, idx) => {
      // User message
      if (m.u) {
        messages.push({
          id: `m_${id}_${idx}_u`,
          text: m.u,
          sender: 'customer',
          timestamp: lastTime.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })
        });
        lastTime.setMinutes(lastTime.getMinutes() + Math.floor(Math.random() * 5) + 1);
      }
      // Shop reply (if any)
      if (m.s) {
        messages.push({
          id: `m_${id}_${idx}_s`,
          text: m.s,
          sender: 'user',
          timestamp: lastTime.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })
        });
        lastTime.setMinutes(lastTime.getMinutes() + Math.floor(Math.random() * 10) + 1);
      }
    });

    const lastMessage = messages[messages.length - 1];

    // Determine unread count: 30% chance of being unread if last sender was customer
    let unreadCount = 0;
    if (lastMessage.sender === 'customer' && Math.random() > 0.7) {
      unreadCount = Math.floor(Math.random() * 3) + 1;
    }

    // Friendly timestamp formatting
    const now = new Date();
    const diffHours = (now.getTime() - lastTime.getTime()) / (1000 * 60 * 60);
    let timeDisplay = lastTime.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
    if (diffHours < 1) timeDisplay = 'Vừa xong';
    else if (diffHours < 24) timeDisplay = lastTime.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
    else timeDisplay = `${lastTime.getDate()}/${lastTime.getMonth() + 1}`;

    return {
      id,
      customerName,
      avatar,
      platform,
      lastMessage: lastMessage.text,
      timestamp: timeDisplay,
      unreadCount,
      messages,
      sender: lastMessage.sender // used to check who sent last
    };
  }).sort((a, b) => {
     // Simple sort logic: Put unread first, then just shuffle a bit for demo or rely on generation order
     if (a.unreadCount > 0 && b.unreadCount === 0) return -1;
     if (a.unreadCount === 0 && b.unreadCount > 0) return 1;
     return 0;
  });
};

