  [Platform.WOOCOMMERCE]: 'https://upload.wikimedia.org/wikipedia/commons/thumb/2/2a/WooCommerce_logo.svg/1200px-WooCommerce_logo.svg.png',
};

const formatCurrency = (value: number) => {
  return new Intl.NumberFormat('vi-VN', { style: 'currency', currency: 'VND', maximumFractionDigits: 0 }).format(value);
};

const StatCard: React.FC<{ title: string; value: string; trend: string; isPositive: boolean; icon: React.ReactNode, bgColor?: string }> = ({ 
  title, value, trend, isPositive, icon, bgColor = 'bg-white' 
}) => (
  <div 
    className={`${bgColor} p-6 rounded-xl shadow-sm border border-slate-200 transition-all duration-300 hover:shadow-md group cursor-default`}
  >
    <div className="flex justify-between items-start mb-4">
      <div className="p-2.5 bg-indigo-50 rounded-lg text-indigo-600 group-hover:bg-indigo-600 group-hover:text-white transition-colors">
        {icon}
      </div>
      <span className={`flex items-center text-xs font-bold px-2 py-1 rounded-full border ${isPositive ? 'bg-emerald-50 text-emerald-700 border-emerald-100' : 'bg-red-50 text-red-700 border-red-100'}`}>
        {isPositive ? <ArrowUpRight size={14} className="mr-1" /> : <ArrowDownRight size={14} className="mr-1" />}
        {trend}
      </span>
    </div>
    <h3 className="text-slate-500 text-sm font-medium mb-1">{title}</h3>
    <p className="text-2xl font-bold text-slate-800 tracking-tight">{value}</p>
  </div>
);

