        <StatCard title="Đơn hàng mới" value={totalOrders.toString()} trend="5.2%" isPositive={true} icon={<ShoppingCart size={20} />} />
        <StatCard title="Cảnh báo tồn kho" value={lowStockProducts.length.toString()} trend="Cần nhập" isPositive={false} icon={<AlertTriangle size={20} />} />
        <StatCard title="Khách hàng mới" value="1,203" trend="8.1%" isPositive={true} icon={<Users size={20} />} />
