                      </div>
                      <div className="flex justify-between text-[10px] text-slate-400">
                         <span>{shop.orders} đơn hàng</span>
                         <span>{((shop.revenue / maxShopRevenue) * 100).toFixed(0)}% dẫn đầu</span>
