                                        type="number" 
                                        value={config.value}
                                        onChange={(e) => setBulkProductConfigs(prev => ({...prev, [p.id]: { ...config, value: Number(e.target.value) }}))}
                                        className="w-16 p-1 text-center text-sm outline-none font-bold text-orange-700"
