                    </td>
                    <td className="px-4 py-3 text-center">
                        {isChecked ? (
                            <input 
                                type="number"
                                min="1"
                                max="1000"
                                value={config.stock}
                                onChange={(e) => setBulkProductConfigs(prev => ({...prev, [p.id]: { ...config, stock: Number(e.target.value) }}))}
